(window.courseContentFiles = window.courseContentFiles || {})["000003/0007"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>document</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 7px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n      padding: 5px 7px;\n      border: 1px solid #d8e5d4;\n      border-radius: 9px;\n      background: #f4f9f2;\n    }\n    .audio-link-icon {\n      width: 26px;\n      height: 26px;\n      border: 1px solid #588157;\n      border-radius: 8px !important;\n      background: transparent;\n      color: #2f5d50;\n      cursor: pointer;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 26px;\n      padding: 0;\n      text-align: center;\n      font-size: 12px;\n      font-weight: 700;\n    }\n    .audio-link-icon img,\n    .audio-time {\n      display: none !important;\n    }\n    .audio-link-label {\n      max-width: 125px;\n      min-width: 0;\n      font-size: 0.82em;\n      font-weight: 700;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .audio-link-label:empty {\n      display: none;\n    }\n    .audio-progress {\n      width: 118px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-volume {\n      width: 44px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-progress,\n    .audio-volume {\n      height: 4px;\n      appearance: none;\n      -webkit-appearance: none;\n      background: transparent;\n    }\n    .audio-link-inline audio {\n      display: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Тема 20. Артериална хипертония – видове. Съдови и органни промени.</h1><p><strong>Артериалната хипертония</strong> в големия кръг на кръвообращението се означава като <strong>системна хипертония</strong>. Според СЗО за хипертония се приема повишаване на артериалното налягане над <strong>160 mmHg систолно</strong> и <strong>95 mmHg диастолно</strong>. Стойности под <strong>140/90 mmHg</strong> се считат за нормални, а между <strong>140/90 и 160/95 mmHg</strong> се определят като <strong>гранична хипертония</strong>.</p><p>Според по-съвременна класификация при възрастни нормалното налягане е под <strong>130/85 mmHg</strong>, а стойности <strong>130–139/85–89 mmHg</strong> се приемат за горна граница на нормата. Артериалната хипертония се разделя на стадии според повишаването на систолното и диастолното налягане.</p><p>Артериалната хипертония е често заболяване, което дълго може да протича безсимптомно. Значението ѝ е голямо, защото участва в развитието на <strong>миокарден инфаркт</strong>, <strong>инсулт</strong>, хронично бъбречно заболяване и аортна дисекация.</p><p>Артериалното налягане зависи основно от <strong>сърдечния дебит и периферната съдова резистентност</strong>. Те се влияят от кръвния обем, Na⁺ хомеостазата, хуморални фактори, локални съдови механизми, генетична предразположеност и фактори на околната среда.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Видове артериална хипертония</h2><p>Според етиологията артериалната хипертония бива <strong>първична</strong> и <strong>вторична</strong>.</p><h3>Първична артериална хипертония</h3><p>В около <strong>90–95%</strong> от случаите причината е неизвестна. Означава се още като <strong>есенциална</strong> или <strong>идиопатична хипертония</strong>.</p><p>Смята се, че има <strong>комплексна генеза</strong>, при която взаимодействат генетични фактори и фактори на околната среда. Основно значение имат нарушенията в регулацията на кръвния обем и периферната съдова резистентност. При продължителна хипертония се включват и бъбреците, особено чрез нарушения в отделянето на Na⁺ и вода.</p><p>Към факторите на околната среда спадат <strong>стрес</strong>, <strong>затлъстяване</strong>, <strong>тютюнопушене</strong>, <strong>намалена двигателна активност и повишен прием на сол</strong>. Те могат да усилят генетичното предразположение.</p><p>В патогенезата участват повишен кръвен обем, увеличена периферна резистентност и хронични вазоконстрикторни влияния. Продължителната вазоконстрикция води до структурни промени в съдовата стена — <strong>задебеляване, ригидност и поддържане на високото налягане</strong>.</p><p>Продължителната хипертония стимулира <strong>атерогенезата</strong>, а атеросклерозата допълнително поддържа хипертонията, създавайки порочен кръг.</p><h3>Вторична артериална хипертония</h3><p>Вторичната хипертония има установима причина. Най-често е свързана с <strong>бъбречни заболявания</strong>, като гломерулонефрити, хронично бъбречно заболяване, бъбречна поликистоза и реновазална хипертония.</p><p>По-рядко възниква при <strong>ендокринни заболявания </strong>— синдром на Cushing, първичен алдостеронизъм, феохромоцитом, акромегалия, хипо- или хипертиреоидизъм. Може да се наблюдава и при <strong>коарктация на аортата</strong>, васкулити, увеличен интраваскуларен обем, увеличен сърдечен дебит, ригидност на аортата, повишено интракраниално налягане, сънна апнея и остър стрес.</p><p>При <strong>реновазална хипертония </strong>стенозата на бъбречната артерия намалява бъбречната перфузия и активира <strong>ренин-ангиотензин-алдостероновата система</strong>. Ангиотензин II причинява вазоконстрикция, а алдостеронът води до задръжка на Na⁺ и вода, което повишава кръвния обем и артериалното налягане.</p><p>При <strong>феохромоцитом </strong>повишената секреция на катехоламини води до вазоконстриктивна хипертония и хипергликемия.</p><p>Артериалната хипертония е важен рисков фактор за <strong>исхемична болест на сърцето</strong>, <strong>миокарден инфаркт</strong>, <strong>инсулт</strong>, <strong>хронично бъбречно заболяване </strong>и <strong>аортна дисекация</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Протичане на артериалната хипертония</h2><h3>Бенигнена хипертония</h3><p>При <strong>бенигнена хипертония</strong> артериалното налягане е умерено повишено и обикновено не надвишава <strong>200/110 mmHg</strong>. Заболяването дълго време протича безсимптомно или с минимални клинични прояви, докато се развият органни усложнения.</p><p>Артериалната хипертония е основен рисков фактор за <strong>исхемична болест на сърцето</strong>, мозъчносъдова болест, <strong>левокамерна хипертрофия</strong> със сърдечна недостатъчност, аортни дисекации и бъбречна недостатъчност.</p><h3>Малигнена хипертония</h3><p>При <strong>малигнена хипертония</strong> артериалното налягане се покачва бързо и за кратко време достига много високи стойности — над <strong>200 mmHg систолно</strong> и над <strong>120 mmHg диастолно</strong>.</p><p>Органните усложнения настъпват рано, а медикаментозният контрол обикновено е труден. Най-важно е засягането на <strong>малките артерии и артериолите</strong>, където се развива <strong>фибриноидна некроза </strong>и некротизиращ артериолит. В бъбреците това води до исхемично увреждане и некроза на тубулите, с развитие на <strong>бъбречна недостатъчност</strong>.</p><p>Характерни са и промени в ретината — <strong>хеморагии и ексудати</strong>, със или без <strong>оток на папилата</strong>.</p><p>Малигнената хипертония най-често се развива върху предшестваща <strong>есенциална или вторична хипертония</strong>, но по-рядко може да възникне и при нормотоници.</p><p>Водещите функционални и структурни промени са в <strong>лявата камера</strong> и в артериалната мрежа, най-вече в <strong>артериолите </strong>и малките мускулни артерии. Промените в големите артерии настъпват по-късно.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Стадии на артериалната хипертония</h2><h3>Първи стадий – функционален</h3><p>В този стадий преобладават функционални промени. Може да има <strong>хипертрофия на лявата камера</strong>, но тя може и все още да липсва.</p><h3>Втори стадий – стадий на съдови промени</h3><p>Характеризира се със съдови изменения, най-вече в <strong>артериолите</strong>. Основна промяна е <strong>хиалинизацията на артериолите</strong>, като най-отчетливи са промените в бъбреците.</p><p>В бъбреците се засяга предимно <strong>аферентната артериола</strong> на гломерула, докато при диабет се засягат както аферентната, така и еферентната артериола.</p><p>Могат да се наблюдават още:</p><ul><li><strong>миоеластофиброза</strong>;</li><li><strong>хиперпластична артериолосклероза</strong>;</li><li><strong>фибриноидна некроза</strong> при малигнена хипертония.</li></ul><h3>Трети стадий – стадий на органни увреждания</h3><p>В този стадий настъпват трайни органни промени в резултат на дълготрайна съдова увреда.</p><p>Най-важни прояви са <strong>артериолосклеротична нефросклероза</strong>, <strong>исхемична болест на сърцето</strong> и <strong>мозъчносъдова болест</strong>.</p><p>При артериолосклеротична нефросклероза бъбреците са <strong>малки</strong>, с червеникав цвят, <strong>дребнозърниста повърхност</strong> и изтънена кора.</p><p>В мозъка хипертонията може да доведе до мозъчносъдова болест с <strong>лакунарни инфаркти</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Съдови промени при артериална хипертония</h2><p>Най-рано се увреждат <strong>артериолите</strong> и малките мускулни артерии. Основните форми са <strong>хиалинна артериолосклероза</strong> и <strong>хиперпластична артериолосклероза</strong>.</p><h3>Хиалинна артериолосклероза</h3><p>Това е главната морфологична проява на продължителна <strong>бенигнена хипертония</strong>. Засяга артериолите.</p><p><strong>Микроскопски</strong> се характеризира с отлагане на еднородна <strong>хиалинна материя</strong> в субендотелното пространство. Това води до задебеляване на стената и стеснение на артериоларния лумен, с намалено кръвоснабдяване на засегнатите органи.</p><p>Най-добре се проявява в бъбреците. Дифузната бъбречна исхемия води до <strong>артериолосклеротична нефросклероза</strong>, при която бъбреците са симетрично и двустранно дребнозърнести.</p><h3>Хиперпластична артериолосклероза</h3><p>Наблюдава се при по-тежки форми на хипертония и при <strong>малигнена хипертония</strong>. Засяга по-големи артериални съдчета.</p><p><strong>Микроскопски</strong> се проявява със задебеляване на съдовата стена и стеснение на лумена поради <strong>концентрична пролиферация</strong> на гладкомускулни клетки в субендотелното пространство. Медията е задебелена, а еластичната мембрана — задебелена и разслоена.</p><p>При малигнена хипертония често се добавят <strong>фибриноидни отлагания</strong> и <strong>фибриноидна некроза</strong>. Развива се <strong>некротизиращ артериолит</strong> с тромби в съдовия лумен и множество остри исхемични огнища. Промените са най-изразени в бъбреците, надбъбреците и чревния тракт.</p><h3>Промени в големите артерии</h3><p>При продължителна хипертония големите артерии развиват <strong>хипертонична артериопатия</strong>.</p><p><strong>Макроскопски</strong> се наблюдава задебеляване на медията поради хипертрофия на гладкомускулните клетки.</p><p><strong>Микроскопски</strong> по интимата могат да се видят микродефекти в ендотела, които улесняват появата и развитието на <strong>атеросклеротични плаки</strong>. Затова артериалната хипертония е основен рисков фактор за атеросклероза и води до по-ранна и по-тежка изява.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хипертонична болест на сърцето</h2><p><strong>Хипертоничната болест на сърцето</strong> е адаптивна реакция на сърцето към повишеното натоварване при системна артериална хипертония.</p><p>Диагностични критерии са:</p><ul><li>наличие на <strong>лявокамерна хипертрофия</strong>, обикновено концентрична;</li><li>липса на друго сърдечно заболяване, което би могло да причини такава хипертрофия;</li><li>анамнеза за системна артериална хипертония.</li></ul><p><strong>Макроскопски:</strong> основната проява е <strong>хипертрофия на лявата камера</strong>, която обхваща стената симетрично по цялата ѝ обиколка — <strong>концентрична хипертрофия</strong>. Лявокамерната стена достига дебелина <strong>над 2 cm</strong>, а сърдечното тегло може да надхвърли <strong>500 g</strong>.</p><p><strong>Микроскопски:</strong> кардиомиоцитите са увеличени, с нараснал диаметър и уголемени хиперхромни ядра. При продължителна хипертония, особено при съпътстваща коронарна атеросклероза и ИБС, се развиват <strong>дифузна интерстициална фиброза</strong> и атрофия на кардиомиоцити с исхемични промени.</p><p>Хипертрофията на лявата камера първоначално е <strong>адаптивна реакция</strong>, но с времето води до <strong>диастолно напълване</strong>, миокардна дисфункция, сърдечна дилатация и хронична сърдечна недостатъчност.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 21. Аневризми – видове, морфологична характеристика.</h1><p><strong style=\"color: rgb(31, 41, 55)\">Аневризма</strong><span style=\"color: rgb(31, 41, 55)\"> е ограничено абнормно разширение на съдовия просвет. Равномерното разширение по дължината на кръвоносния съд се означава като </span><strong style=\"color: rgb(31, 41, 55)\">ангиектазия</strong><span style=\"color: rgb(31, 41, 55)\">.</span></p><h3>Класификация според структурата</h3><ul><li><strong>Истинска аневризма</strong> – стената ѝ е изградена от всички слоеве на съдовата стена, макар и изтънени. Такива са <strong>атеросклеротичните</strong>, <strong>луетичните</strong> и <strong>вродените аневризми</strong>.</li><li><strong>Лъжлива аневризма / псевдоаневризма</strong> – представлява околосъдов хематом, който комуникира със съдовия просвет, т.е. <strong>„пулсиращ хематом“</strong>. Възниква при частично или пълно разкъсване на съдовата стена, а стената ѝ е изградена от адвентиция, перивазална тъкан или кръвни елементи. Среща се например около съдови протези или като усложнение на истинска аневризма.</li></ul><h3>Класификация според произхода</h3><ul><li><strong>Вродени аневризми</strong> – дължат се на дефекти в развитието на артериалната стена. Срещат се по-често при жени и най-често се локализират в базалната съдова мрежа на главния мозък.</li><li><strong>Придобити аневризми</strong> – развиват се при отслабване на съдовата стена вследствие на инфекциозни или системни васкулити, травми, дегенеративни и атеросклеротични промени.</li></ul><h3>Класификация според макроскопския вид</h3><h4>Вретеновидни / фузиформени аневризми</h4><p>При тях аневризмалното разширение постепенно намалява и преминава към незасегнатия съдов сегмент. Главната причина за възникването им е <strong>атеросклерозата</strong>.</p><p>Срещат се около 5 пъти по-често при мъже, обикновено след <strong>40–50-годишна възраст</strong>. Най-често се локализират в <strong>абдоминалната аорта</strong>, но могат да се наблюдават и в общите илиачни артерии, аортната дъга и гръдната аорта.</p><p><strong>Макроскопски</strong> атеросклеротичните аневризми на абдоминалната аорта могат да достигнат големи размери — до 15 cm в най-широката част и 20–25 cm по дългата ос. По интималната повърхност има множество <strong>атеросклеротични плаки</strong>, често с насложени пристенни тромби с различна големина и давност.</p><p><strong>Микроскопски</strong> се наблюдава картина на многообразие на усложнени атеросклеротични плаки.</p><p><strong>Клиничната изява</strong> зависи от големината на аневризмата и наличието на тромботични отлагания:</p><ul><li><p><strong>тромбоемболии</strong> в дистални артерии</p><br></li><li><p>запушване на остиуми на големи артериални клонове (мезентериални, бъбречни или вертебрални артерии) </p><p>от пристенни тромби</p><br></li><li><p>клинична „маска“ на абдоминален тумор с компресия на съседни органи (уретер), ерозия на телата на гръбначни прешлени, но най-често с доловими палпаторно пулсации</p><br></li><li><p>Руптура с масивен абдоминален кръвоизлив.</p><br></li></ul><p>Сравнително рядко се срещат <strong>микотични абдоминални аневризми</strong>. Те представляват атеросклеротични аневризми с насложено възпаление от циркулиращи микроорганизми (салмонела). Възпалението ускорява деструкцията на стената и води до по-бърза дилатация и руптура.</p><h3>Торбовидни / сакциформени аневризми</h3><p>Обикновено са със сферична форма и най-често са с <strong>луетична генеза</strong>. Срещат се по-често при мъже между <strong>40–55 години</strong>.</p><p>При третичен сифилис се развива <strong>облитеративен ендартериит</strong> на малките съдове, като една от най-характерните прояви е засягането на <strong>vasa vasorum</strong> на аортата. Това води до <strong>луетичен аортит</strong> и деструкция на аортната медия.</p><p>За разлика от повечето атеросклеротични аневризми, луетичната аневризма най-често се локализира във <strong>възходящата аорта</strong>. Може да достигне 15–20 cm в диаметър. Интималната повърхност има характерен вид на <strong>„кора на дърво“</strong> или <strong>„портокалова кора“</strong>.</p><p>С прогресията могат да се развият вторични атеросклеротични плаки и пристенни тромби. Въвличането на корена на аортата води до <strong>аортна клапна недостатъчност</strong> и може да засегне коронарните артерии.</p><p><strong>Микроскопски </strong>- вж. Луетичен аортит</p><p><strong>Клинично</strong> аневризмите на гръдната аорта могат да наподобяват медиастинален тумор като се проявяват с:</p><ul><li><p>затруднено дишане - от притискане на дихателните пътища и белите дробове</p></li><li><p>затруднено преглъщане - от притискане на хранопровода</p></li><li><p>суха дразнеща кашлица и гласови промени - от притискане на ларингеалните нерви</p></li><li><p>болки в гръдната област - от ерозия на ребра, гръдна кост или тела на гръбначни прешлени.</p></li></ul><p>Тези прояви могат да се съчетаят с <strong>аортна клапна недостатъчност</strong>, ИБС и тромбоемболични усложнения. <strong>Руптурата</strong> на аневризмалния сак завършва с фатален кръвоизлив. Повечето болни с луетични аневризми умират от сърдечна недостатъчност поради аортна клапна инсуфициенция.</p><p>Аортните аневризми, независимо от вида и произхода си, подлежат на оперативно лечение чрез поставяне на <strong>съдова протеза</strong> на мястото на аневризмалния сегмент.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 22. Васкулити – класификация, морфологична характеристика.</h1><p><strong>Васкулитите</strong> са възпалителни процеси в съдовите стени. Наричат се още <strong>ангиити</strong>, а според засегнатия съд — <strong>артериити</strong> или <strong>флебити</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Етиология</h2><p>Част от васкулитите се причиняват от инфекциозни агенти — пиогенни бактерии, туберкулозни бактерии, <em>Spirocheta pallida</em>, рикетсии, гъбички и вируси като Morbilli, Herpes zoster и Varicella.</p><p>По-голямата част са с неизвестна етиология, като в патогенезата им основно значение имат <strong>имунните процеси</strong>.</p><p>Васкулитите могат да засегнат съдове от всякакъв калибър. Могат да бъдат <strong>локални</strong> или <strong>системни</strong>. Често се усложняват с <strong>тромбози, стенози или облитерация</strong> на съдовия лумен, което води до <strong>тъканна</strong> <strong>исхемия</strong>.</p><p>Клинично могат да протекат с общи прояви като <strong>фебрилитет, артралгии и миалгии</strong>, както и с органоспецифични увреждания.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Класификация на системните васкулити</h2><p>Класификацията се основава на три критерия: <strong>калибър на засегнатите съдове</strong>, <strong>морфологична характеристика на съдовата лезия</strong> и <strong>клинична изява</strong>.</p><h3>Васкулити на големите съдове</h3><p>Засягат <strong>аортата и нейните разклонения</strong> — артерии от еластичен и еластично-мускулен тип.</p><table><tbody><tr><td>Заболяване</td><td>Съдова предилекция</td><td>Морфология</td><td>Главни клинични прояви</td></tr><tr><td><strong>Гигантоклетъчен / темпорален артериит</strong> <em>(Horton)</em></td><td><strong>a. temporalis superficialis</strong></td><td>Сегментен грануломатозен гигантоклетъчен артериит около вътрешната еластична мембрана</td><td>Над 50 г., главоболие, зрителни нарушения, палпаторна болезненост</td></tr><tr><td><strong>Артериит на Takayasu</strong></td><td>Аортна дъга и клоновете ѝ</td><td>Сегментен грануломатозен гигантоклетъчен артериит</td><td>Под 40 г., по-често жени, болест на аортната дъга / безпулсова болест</td></tr></tbody></table><h3>Васкулити на средните съдове</h3><p>Засягат <strong>главните органни артерии и техните клонове</strong>.</p><table><tbody><tr><td>Заболяване</td><td>Съдова предилекция</td><td>Морфология</td><td>Главни клинични прояви</td></tr><tr><td><strong>Polyarteriitis nodosa</strong></td><td>Генерализирано; не засяга белодробните артерии; бъбреци и сърце</td><td>Трансмурален сегментен некротизиращ васкулит</td><td>Инфаркти в бъбреци и сърце</td></tr><tr><td><strong>Болест на Kawasaki</strong></td><td>Коронарни артерии</td><td>Морфологично сходна с polyarteriitis nodosa</td><td>Деца, най-често под 4 г.; кожно-лигавичен лимфновъзлов синдром</td></tr></tbody></table><h3>Васкулити на малките съдове</h3><p>Засягат <strong>артериоли, капиляри, венули</strong>, понякога и малки мускулни артерии.</p><table><tbody><tr><td>Заболяване</td><td>Съдова предилекция</td><td>Морфология</td><td>Главни клинични прояви</td></tr><tr><td><strong>Алергичен васкулит</strong></td><td>Генерализирано; кожа, лигавици, бял дроб</td><td>Левкоцитокластичен васкулит</td><td>Кожна пурпура, кръвохрак, интестинално кървене, хематурия и протеинурия</td></tr><tr><td><strong>Грануломатоза на Wegener</strong></td><td>Дихателни пътища, бял дроб, бъбреци</td><td>Огнищен некротизиращ и грануломатозен васкулит</td><td>По-често при мъже около 40 г.; белодробни инфилтрати, хроничен синуит, улцерации в назофаринкса, гломерулонефрит</td></tr><tr><td><strong>Синдром на Churg-Strauss</strong></td><td>Бели дробове</td><td>Сегментен некротизиращ васкулит</td><td>Алергичен ринит, бронхиална астма, еозинофилия</td></tr><tr><td><strong>Пурпура на Henoch-Schönlein</strong></td><td>Кожа, стомашно-чревен тракт, бъбреци / гломерули</td><td>IgA отлагания в съдовите стени</td><td>Кожна пурпура с артралгии и артрити</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Васкулити на големите съдове</h2><p>Засягат <strong>аортата и нейните клонове</strong> — артерии от еластичен и еластично-мускулен тип.</p><h3>Гигантоклетъчен / темпорален артериит</h3><p><strong>Синоним:</strong> артериит на Horton.</p><p>Засяга <strong>аортата</strong> и големите артерии, особено <strong>a. temporalis</strong>, както и артериите към очните булбуси. Среща се главно над <strong>50-годишна възраст</strong>. Етиологията и патогенезата са неизвестни.</p><p><strong>Микроскопски</strong> в острия стадий се различават два варианта:</p><ul><li><strong>Първи вариант — грануломатозен:\n</strong>В повечето случаи се наблюдава <strong>сегментен грануломатозен възпалителен процес</strong> във вътрешната половина на медията. Характерни са <strong>мононуклеарни инфилтрати</strong>, фрагментация на <strong>вътрешната еластична мембрана</strong> и гигантски клетки тип <strong>Langhans</strong> или тип „чуждо тяло“, концентрирани около разрушената еластична мембрана. В някои гигантски клетки се откриват фагоцитирани фрагменти от мембраната.</li><li><strong>Втори вариант — негрануломатозен:\n</strong>Грануломатозните промени са редки или липсват. Възпалителният инфилтрат съдържа <strong>лимфоцити и макрофаги</strong>, с примес от неутрофилни и еозинофилни левкоцити. Гигантски клетки не се откриват. В част от случаите може да има <strong>фибриноидна некроза</strong>.</li></ul><p>В късните оздравителни стадии и при двата варианта се развива <strong>фиброза на съдовата стена</strong> със стеноза на лумена. Организацията на тромби може да превърне артерията във фиброзна връв.</p><p><strong>Клинично</strong> заболяването протича с лицеви болки, силно и упорито главоболие, често едностранно. При засягане на повърхностната темпорална артерия има палпаторна болезненост и нодуларност по хода ѝ. Около половината болни имат зрителни смущения — от диплопия до транзиторна или трайна загуба на зрение. Заболяването се повлиява добре от <strong>кортикостероиди</strong>.</p><h3>Артериит на Takayasu</h3><p><strong>Синоними:</strong> безпулсова болест, синдром на аортната дъга.</p><p>Представлява <strong>грануломатозен васкулит</strong> на артерии от еластичен тип, с предилекция към <strong>аортната дъга</strong> и нейните клонове. В част от случаите се засягат и други сегменти на аортата, нейните клонове и белодробните артерии. Боледуват предимно <strong>жени под 40 години</strong>. Етиологията е неизвестна, но се предполага участие на имунни механизми.</p><p><strong>Макроскопски</strong> се установява силно задебеляване на аортната дъга и проксималните части на нейните клонове. Устията и лумените им са изразено стенотични. Подобни промени могат да се наблюдават и в коронарните и бъбречните артерии.</p><p><strong>Микроскопски</strong> началните промени са в адвентицията — маншоноподобни мононуклеарни инфилтрати около <strong><span class=\"editor-note\" data-note=\"**Vasa vasorum** са малки кръвоносни съдове, които кръвоснабдяват стените на големите артерии и вени.\" id=\"note-1778001808882-0\">vasa vasorum</span></strong>. По-късно инфилтратите обхващат медията, където се виждат огнищни некрози и грануломатозни изменения с гигантски клетки. В късните стадии настъпва склероза на всички слоеве на съдовата стена, с няколкократно задебеляване. Особено изразена е <strong>интималната фиброза</strong>, която води до нишковидно стесняване на лумена.</p><p><strong>Клинично</strong> при засягане на аортната дъга се развива исхемия в горната част на тялото, отслабен или липсващ пулс на горните крайници, парестезии и склонност към синкоп. При засягане на корена на аортата може да настъпи <strong>аортна клапна инсуфициенция</strong>, а при въвличане на коронарните артерии — миокарден инфаркт. Засягането на белодробните артерии води до <strong>белодробна хипертония</strong> и белодробно сърце. Заболяването се повлиява добре от кортикостероиди, но част от болните умират рано от съдов дефицит.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Васкулити на средните съдове</h2><p>Засягат <strong>главните органни артерии и техните клонове</strong>.</p><h3>Polyarteritis nodosa</h3><p><strong>Синоними:</strong> panarteritis nodosa, periarteritis nodosa, болест на Kussmaul-Maier.</p><p><strong>Определение:\n</strong>Нодозният полиартериит е <strong>трансмурален сегментен некротизиращ васкулит</strong> на средните и малките мускулни артерии. Засяга съдове в различни тъкани и органи, но <strong>не засяга клоновете на белодробната артерия</strong>.</p><p><strong>Честота и локализация:\n</strong>Най-често се засягат <strong>бъбречните артерии</strong>, <strong>коронарните артерии</strong>, артериите в черния дроб, стомашно-чревния тракт, панкреаса, тестисите, скелетната мускулатура, нервната система и кожата.</p><p><strong>Макроскопски:\n</strong>По хода на повърхностно разположени артерии, включително под епикарда и в мезентериума, се виждат броеницовидно разположени сивожълтеникави възелчета с размер около <strong>1–2 mm</strong>.</p><p><strong>Микроскопски:\n</strong>Различават се няколко фази в еволюцията на съдовите промени:</p><ul><li><strong>Остра фаза:</strong> фибриноидна некроза в интимата и вътрешната половина на медията, с обилна трансмурална инфилтрация от неутрофили, еозинофили и мононуклеари. Вътрешната еластична мембрана е разрушена. Често има аневризмални издувания и тромботични отлагания.</li><li><strong>По-късна фаза:</strong> инфилтратът е предимно от мононуклеари и пролифериращи фибробласти, които причиняват възловидно адвентициално задебеляване.</li><li><strong>Напреднал стадий:</strong> младата гранулационна тъкан съзрява и се превръща в богата на колаген фиброзна тъкан.</li></ul><p>Характерно е <strong>тласъчното протичане</strong> — различни стадии на възпалителна активност могат да съжителстват в различни артерии или дори в една и съща артерия.</p><p><strong>Клиника:\n</strong>Клиничната изява зависи от локализацията и тежестта на съдовото засягане. Най-важни са <strong>исхемичните увреждания и инфарктите</strong>, особено в бъбреците и сърцето.</p><h3>Болест на Kawasaki</h3><p><strong>Определение:\n</strong>Болестта на Kawasaki е <strong>сегментен некротизиращ артериит</strong>, засягащ големи, средни и малки мускулни артерии, особено често <strong>коронарните артерии</strong>. Среща се предимно при деца и протича с <strong>кожно-лигавичен лимфнонодуларен синдром</strong>.</p><p><strong>Етиология:\n</strong>Не е известна. В патогенезата се приема водеща роля на автоантитела срещу <strong>ендотелни и гладкомускулни клетки</strong>.</p><p><strong>Честота:\n</strong>Заболяват предимно деца, като около <strong>80%</strong> от случаите са под <strong>4-годишна възраст</strong>.</p><p><strong>Клиника:\n</strong>Засягането на коронарните артерии може да бъде безсимптомно или да доведе до аневризми и тромби. Най-тежките усложнения са <strong>руптура на аневризми</strong> и <strong>миокардни инфаркти</strong>.</p><p>В острата фаза се наблюдават фебрилитет, конюнктивит, палмарен и плантарен еритем, кожни обриви с десквамация и неспецифичен лимфаденит на шийните лимфни възли.</p><p><strong>Макроскопски:\n</strong>Артериалните промени наподобяват тези при нодозен полиартериит, но обикновено <strong>фибриноидната некроза</strong> и възпалителната инфилтрация са по-слабо изразени. Измененията варират от леки интимални промени до некротизиращ васкулит с аневризмални и тромботични усложнения.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Васкулити на малките съдове</h2><p>Засягат <strong>артериоли, капиляри и венули</strong>, а понякога и малки мускулни артерии.</p><h3>Алергичен васкулит</h3><p><strong>Синоними:</strong> хиперергичен васкулит, левкоцитокластичен васкулит.</p><p>Проявява се в артериолите, капилярите и венулите. За разлика от <strong>нодозния полиартериит</strong>, съдовите лезии са в <strong>един и същи стадий на развитие</strong>.</p><p><strong>Локализация:</strong> най-често се засягат кожа, лигавици, бели дробове, главен мозък, сърце, стомашно-чревен тракт, бъбреци и скелетни мускули.</p><p><strong>Клиника:</strong> наблюдават се кръвохрак, хематурия с протеинурия, болки и интестинално кървене, миалгии, а кожното засягане се проявява с <strong>болезнена пурпура</strong>.</p><p><strong>Микроскопски:</strong> установява се сегментна <strong>фибриноидна некроза</strong> в медията и инфилтрация с неутрофилни левкоцити. При навлизане в съдовата стена те се фрагментират — <strong>левкоцитоклазия</strong>.</p><h3>Грануломатоза на Wegener</h3><p>Заболяването се характеризира с триада:</p><ul><li><strong>некротизиращи грануломи</strong> в горните и/или долните дихателни пътища;</li><li><strong>огнищен некротизиращ или грануломатозен васкулит</strong> на малките съдове, най-изразен в белите дробове и горните дихателни пътища;</li><li><strong>гломерулонефрит</strong> — в началото огнищен с некрози на капилярните бримки, а по-късно полулунен, с развитие на бъбречна недостатъчност.</li></ul><h3>Синдром на Churg-Strauss</h3><p><strong>Синоним:</strong> алергична грануломатоза и ангиит.</p><p>Съдовите изменения наподобяват тези при <strong>нодозния полиартериит</strong>. Заболяването се съчетава с <strong>алергичен ринит</strong>, <strong>бронхиална астма</strong> и <strong>еозинофилия</strong> в периферната кръв.</p><p>В грануломатозните огнища също се открива изобилие от <strong>еозинофилни левкоцити</strong>. Засягат се съдовете в белите дробове, сърцето, слезката, периферната нервна система и кожата.</p><h3>Пурпура на Henoch-Schönlein</h3><p>Представлява васкулит с <strong>IgA имунни отлагания</strong> в малките съдове — артериоли, капиляри и венули — на кожата, чревния тракт и бъбречните гломерули.</p><p>Съпровожда се с <strong>артралгии или артрит.</strong></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 23. Съдови заболявания – болест на Рейно, болест на Бюргер.</h1><h2>Облитериращ тромбангиит</h2><p><strong>Синоним:</strong> болест на Buerger.</p><p>Болестта на Buerger е самостоятелно съдово заболяване с неизвестна етиология. Характеризира се със <strong>сегментно остро и хронично възпаление с тромбози</strong> в средните и малките артерии на крайниците, главно <strong>тибиални и радиални артерии</strong>. Понякога вторично се въвличат съпътстващите вени и нерви.</p><p>Заболяването се среща почти изключително при <strong>мъже под 35 години</strong>. В патогенезата голямо значение има <strong>тютюнопушенето</strong>. Повечето болни са тежки пушачи, а спирането на тютюнопушенето в ранните стадии често прекъсва прогресията. Допуска се и участие на генетични фактори.</p><p><strong>Клиника:</strong> ранните прояви са чувствителност към студ, клаудикация и повърхностен нодуларен флебит. За разлика от атеросклеротичната артериална недостатъчност, болките са по-силни поради засягане на нервите.</p><p><strong>Макроскопски:</strong> засегнатите артерии са вървовидно уплътнени и изпълнени с тромботични отлагания в различна фаза на организация. В по-късните стадии има периартериална фиброза, която обхваща съседните нерви и вени.</p><p><strong>Микроскопски:</strong> артериалната стена е <strong>възпалително инфилтрирана</strong>, особено в интимата под вътрешната еластична мембрана, която остава запазена. Луменът е тромбозиран, а в тромбите се откриват характерни <strong>микроабсцеси</strong> с централни неутрофили, заобиколени от лимфоцити и макрофаги. Постепенно тромбите се организират, възпалението обхваща периартериалната тъкан, вените и нервите, като може да се развие <strong>панфлебит с множество тромби</strong>.</p><p>В хроничните стадии възпалителната инфилтрация намалява, тромбите се реканализират и се развива <strong>фиброза на артериалната стена и периартериалната тъкан</strong>.</p><p><strong>Изход:</strong> прогресиращата исхемия води до некрози и разязвявания по върховете на пръстите, включително до <strong>гангрена</strong>, която може да наложи ампутация.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Болест на Raynaud</h2><p>Болестта на Raynaud се характеризира с пристъпи на <strong>бледост или цианоза</strong> по пръстите на крайниците, по-рядко по носа и ушите, обикновено при млади жени без данни за друго заболяване.</p><p>Приема се, че се дължи на <strong>вазоконстрикция</strong> на малките артерии и артериоли в отговор на студови или емоционални дразнения. Органични съдови промени обикновено липсват, освен при продължително протичане, когато може да се развие интимална пролиферация.</p><p>Прогнозата е добра. При продължително протичане могат да настъпят атрофични промени в кожата и подлежащата мускулатура, а улцерации се развиват рядко.</p><p><strong>Феноменът на Raynaud</strong> се различава от болестта на Raynaud. Той представлява вторична артериална недостатъчност на крайниците поради стеснение на артериите при други заболявания, като <strong>системен лупус еритематодес</strong>, <strong>системна склероза</strong> и <strong>болест на Buerger</strong>. В тези случаи може да бъде ранна или първа проява на основното заболяване.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 24. Артериосклероза – видове. Атеросклероза. Етиология, патогенеза, морфогенеза.</h1><p><strong style=\"color: rgb(31, 41, 55)\">Артериосклероза</strong><span style=\"color: rgb(31, 41, 55)\"> е общ термин за заболявания, при които настъпва </span><strong style=\"color: rgb(31, 41, 55)\">удебеляване и загуба на еластичност на артериалната стена</strong><span style=\"color: rgb(31, 41, 55)\">. Основни видове:</span></p><ul><li><strong>Атеросклероза</strong> – засяга големи и средни артерии</li><li><strong>Артериолосклероза</strong> – засяга малки съдове (често при хипертония/диабет)</li><li><strong>Медиална калцифицираща склероза (на Mönckeberg)</strong></li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h3>Атеросклероза – значение</h3><p>Атеросклерозата има <strong>изключително голямо значение</strong>, защото засяга:</p><ul><li><strong>аортата</strong></li><li><strong>коронарните артерии</strong></li><li><strong>мозъчните артерии</strong></li></ul><p>→ води до <strong>исхемична болест на сърцето (ИБС)</strong>, <strong>мозъчни инфаркти</strong> и <strong>аневризми</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Първостепенни и второстепенни рискови фактори при атеросклероза</h2><p>Развитието и клиничната изява на атеросклерозата зависят от множество <strong>рискови фактори</strong>, които се разделят на <strong>неконтролируеми</strong> и <strong>контролируеми</strong>.</p><h3>Първостепенни рискови фактори</h3><p><strong>Възраст\n</strong>Стареенето има най-силно влияние. Атеросклеротични изменения започват още в детството, но клиничната изява настъпва:</p><ul><li>след <strong>35 г. при мъжете</strong></li><li>след <strong>45 г. при жените</strong></li></ul><p>  С напредване на възрастта честотата на усложненията нараства.</p><p><strong>Пол\n</strong>Мъжете са по-предразположени. Жените до менопауза са относително защитени поради:</p><ul><li><strong>естрогенен протективен ефект</strong></li><li>по-високи нива на <strong>HDL</strong></li></ul><p>След менопауза тази защита намалява и честотата на миокардния инфаркт се изравнява между половете.</p><p><strong>Фамилно предразположение\n</strong>Свързано с:</p><ul><li>наследствени нарушения в <strong>липидния метаболизъм</strong></li><li><strong>фамилна хиперхолестеролемия</strong></li><li>фамилна обремененост за <strong>хипертония</strong> и <strong>диабет</strong></li></ul><h3>Основни контролируеми рискови фактори</h3><p><strong>Хиперлипидемия\n</strong>Най-съществен рисков фактор, особено <strong>хиперхолестеролемията</strong>.</p><ul><li><strong>LDL</strong> → атерогенен ефект</li><li><strong>HDL</strong> → протективен ефект (обратен транспорт на холестерол)</li></ul><p>Високи стойности на HDL намаляват риска, докато генетични и придобити състояния с повишен холестерол го увеличават.</p><p><strong>Артериална хипертония\n</strong>Ускорява атерогенезата и утежнява:</p><ul><li><strong>исхемична болест на сърцето</strong></li><li><strong>мозъчносъдова болест</strong></li></ul><p>Рискът нараства с увеличаване на стойностите на артериалното налягане като след 45 г. тя може да стане по-важен фактор от хиперлипидемията.</p><p><strong>Захарен диабет</strong></p><ul><li>усилва атерогенния ефект на хиперлипидемията</li><li>увеличава честотата на миокардния инфаркт</li><li>значително повишава риска от атеросклеротично обусловена <strong>гангрена на крайниците</strong></li></ul><p><strong>Тютюнопушене</strong></p><ul><li>води до по-тежки и по-разпространени атеросклеротични плаки</li><li>увеличава риска от ИБС и внезапна сърдечна смърт</li><li><p>удвоява смъртността при дългогодишна употреба</p><br></li><li>ефектът намалява след прекратяване</li></ul><h3>Второстепенни рискови фактори</h3><ul><li>намалена <strong>физическа активност</strong></li><li><strong>затлъстяване</strong></li><li>хроничен <strong>стрес</strong> (тип А личност)</li><li><strong>орални контрацептиви</strong></li><li><strong>хиперурикемия</strong></li></ul><h3 style=\"font-weight: bold\">Обобщение</h3><p>Комбинацията от няколко рискови фактора има <strong>синергичен ефект</strong> (по-силен от сбора им). Въпреки това атеросклероза може да се развие и без явни рискови фактори, което подчертава нейното <strong>голямо медико-социално значение</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Морфогенеза на атеросклерозата</h2><p>Съвременното разбиране разглежда атеросклерозата като <strong>„реакция спрямо увреждане“ на ендотела</strong>.</p><h3>Промени при ендотелно увреждане</h3><p>В участъците на <strong>ендотелно увреждане или ендотелна дисфункция</strong> настъпват:</p><p><strong>1. Повишена инсудация на липопротеини (главно LDL)</strong></p><ul><li>натрупване в <strong>субендотелното пространство</strong></li><li>окисление → <strong>оксидативно модифицирани LDL</strong></li><li>улесняват задържането на <strong>моноцити</strong></li><li>фагоцитоза → превръщане в <strong>пенести клетки</strong></li></ul><p><strong>2. Повишена експресия на адхезивни молекули</strong></p><ul><li>(интрацелуларни адхезивни молекули, селектини)</li><li>→ адхезия на <strong>моноцити и тромбоцити</strong></li></ul><p>Увредените ендотелни клетки, макрофагите и тромбоцитите отделят <strong>растежни фактори</strong>, които:</p><ul><li>стимулират <strong>пролиферация на гладкомускулни клетки</strong></li><li>предизвикват <strong>миграция към субендотелното пространство</strong></li></ul><p>Някои от гладкомускулните клетки:</p><ul><li>фагоцитират липиди</li><li>→ превръщат се в <strong>миогенни пенести клетки</strong></li></ul><p><strong>3. Образуване на фиброзна плака\n</strong>Пролифериралите <strong>гладкомускулни клетки</strong> продуцират:</p><ul><li><strong>колаген</strong></li><li><strong>еластин</strong></li><li><strong>протеогликани</strong></li></ul><p>→ натрупването им в лезията води до превръщане на липидното петно във <strong>фиброзна плака</strong>.</p><p>В централната част се натрупва <strong>атероматозна маса</strong>, която е отделена от съдовия лумен чрез <strong>фиброзна капсула</strong> → <strong>атероматозна (фибролипидна) плака</strong>.</p><p>В хода на прогресията настъпват <strong>усложнения на атероматозните плаки</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Морфология на атеросклерозата</h2><p>Проявява се с <strong>липидни петна</strong>, <strong>атеросклеротични плаки</strong> и <strong>усложнени плаки</strong>.</p><h3>Липидни петна</h3><p>Това е <strong>най-ранната проява</strong>.</p><p><strong>Макроскопски</strong> се виждат като жълтеникави петна и ивици по интимата с големина до ~1–1.5 cm, които <strong>не проминират</strong> и не причиняват стеноза. Появяват се още в детска възраст – първо в аортата, по-късно в коронарните артерии.</p><p><strong>Микроскопски</strong> са изградени от:</p><ul><li><strong>пенести клетки</strong> (макрофаги с холестерол и естери)</li><li>малко <strong>гладкомускулни клетки</strong> с липидни включвания (миогенни пенести клетки)</li><li>оскъдни <strong>екстрацелуларни липиди</strong> (от разпад на клетки)</li></ul><p>Характерно е, че <strong>могат да регресират</strong>.</p><h3>Атеросклеротична плака</h3><p>Това е <strong>типичната морфологична изява</strong>.</p><p><strong>Макроскопски</strong> представлява надигнато над интимата огнище (1–3 cm), с овоидна или неправилна форма. При разрез често се вижда <strong>жълтеникаво кашесто ядро</strong>, заобиколено от по-плътна белезникава тъкан. Плаките <strong>проминират и причиняват стеноза</strong>.</p><p><strong>Микроскопски</strong> се състоят от:</p><ul><li><strong>гладкомускулни клетки и макрофаги</strong></li><li><strong>съединителнотъканен матрикс</strong> (колаген, еластин, протеогликани)</li><li><strong>липиди</strong></li></ul><p>В много случаи се оформя <strong>фиброзна капсула</strong>, която огражда централен <strong>атером</strong> (екстрацелуларни липиди, клетъчен детрит, фибрин). В периферията се натрупват <strong>пенести клетки</strong>.</p><p>Допълнително се наблюдават:</p><ul><li><strong>фиброза и атрофия на медията</strong> → намалена еластичност</li><li><strong>ангиогенеза</strong></li><li>възможно <strong>инкорпориране на тромби</strong>, което ускорява растежа</li></ul><h3>Усложнени атеросклеротични плаки</h3><p>Те са отговорни за клиничните прояви.</p><p>В плаките могат да настъпят:</p><ul><li><strong>калцификация</strong> → съдът става ригиден</li><li><strong>фисури и улцерации</strong> → излив на атероматозно съдържимо → <strong>атероемболи</strong></li><li><strong>тромбоза</strong> (пристенна или обтурираща)</li><li><strong>кръвоизлив в плаката</strong> → бързо увеличаване и остра стеноза, възможна руптура</li><li><strong>дисекация</strong> при проникване на кръв в стената</li><li><strong>аневризми</strong> → поради отслабване и загуба на еластичност</li></ul><p>Тези промени определят усложненията като инфаркти, емболии и съдови руптури.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 25. Остра и хронична исхемична болест на сърцето. Морфологична характеристика.</h1><p><strong><span style=\"color: rgb(88, 129, 87)\"><span class=\"editor-note\" data-note=\"## Обща характеристика\nНормалното сърдечно тегло зависи от ръста и телесното тегло. Обикновено е около **250–300 g при жените** и **300–350 g при мъжете**.\nДебелината на свободната стена на **лявата камера** е **1.3–1.5 cm**, а на **дясната камера** — **0.3–0.5 cm**.\nПри много сърдечни заболявания се наблюдават:\n* **хипертрофия** — увеличаване на сърдечното тегло или дебелината на камерните стени;\n* **дилатация** — разширяване на сърдечните кухини;\n* **кардиомегалия** — общо увеличаване на размера и теглото на сърцето.\n## Миокард\nМиокардът е изграден от разклоняващи се и анастомозиращи напречнонабраздени мускулни клетки — **кардиомиоцити**, с централно разположено ядро. Между тях се намират **интеркаларни дискове**, които осигуряват връзката между отделните клетки.\nФункционалната контрактилна единица е **саркомерът**. Той е изграден от дебели **миозинови** и тънки **актинови** филаменти, както и регулаторни протеини — **тропонин** и **тропомиозин**.\nКонтракцията настъпва чрез плъзгане на актиновите филаменти между миозиновите към центъра на саркомера, което води до неговото скъсяване.\n## Проводна система\nПроводната система е изградена от специализирани мускулни клетки, които създават и провеждат импулсите за сърдечно съкращение. Тя осигурява ритмичната и координирана дейност на предсърдията и камерите.\nОсновните ѝ компоненти са:\n* **синоатриален възел (SA)** — pacemaker на сърцето, разположен между дясното сърдечно ухо и горната празна вена;\n* **атриовентрикуларен възел (AV)** — под ендокарда на задната стена на дясното предсърдие;\n* **сноп на His** — преминава към камерния септум и се разделя на дясно и ляво бедро.\n## Клапи\nФункцията на четирите сърдечни клапи е да поддържат **еднопосочен кръвен ток**.\nМакроскопски клапните платна са тънки и полупрозрачни. Покрити са с ендотел и имат слоист строеж:\n* **tunica fibrosa** — плътна съединителнотъканна прослойка откъм изхода на кръвта;\n* **lamina spongiosa** — рехава съединителнотъканна прослойка.\nНормалните клапни платна **нямат кръвоносни съдове**. Хранят се чрез дифузия от кръвта.\n## Перикард\nПерикардната торбичка съдържа около **30–50 ml** бистра, сламеножълта течност. Епикардът и париеталният перикард са изградени от един ред мезотелни клетки върху фиброзна тъканна прослойка.\" id=\"note-1778087491538-5\">Анатомия</span>. <span class=\"editor-note\" data-note=\"## Кръвоснабдяване\nСърцето зависи от адекватен приток на оксигенирана кръв чрез **коронарните артерии**, тъй като енергията за миокардната контракция се осигурява чрез окисление на субстрати.\nДвете главни коронарни артерии — **лява** и **дясна** — излизат от аортата, от синусите на Valsalva, непосредствено под аортната клапа.\n**Лявата коронарна артерия (LCA)** след кратък ход се разделя на **ляв десцендентен клон** и **ляв циркумфлексен клон**. Левият десцендентен клон кръвоснабдява предната стена на лявата камера, голяма част от върха и предните 2/3 от междукамерния септум. Левият циркумфлексен клон кръвоснабдява латералната стена на лявата камера.\n**Дясната коронарна артерия (RCA)** кръвоснабдява свободната стена на дясната камера и задната третина на междукамерния септум.\" id=\"note-1778087589687-6\">Кръвоснабдяване</span>.</span></strong></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>Исхемичната болест на сърцето (ИБС)</strong> е общо наименование за група сродни синдроми, обусловени от <strong>миокардна исхемия</strong> — дисбаланс между кислородните потребности на сърцето и доставката на оксигенирана кръв.</p><p>Най-честата причина е недостатъчно <strong>коронарно артериално кръвоснабдяване</strong> поради <strong>стенозираща атеросклероза</strong> или спазъм на коронарните артерии. Затова ИБС се означава и като <strong>коронарна болест на сърцето</strong>.</p><p>Недостатъчната кислородна доставка може да се дължи и на повишени функционални изисквания на миокарда, например при <strong>хипертония</strong> и тахикардия, или на намален кислороден капацитет на кръвта при тежки анемии и дифузни белодробни заболявания.</p><h2>Честота и рискови фактори</h2><p>ИБС е най-честата причина за смърт в индустриализираните страни, включително България, където причинява около <strong>1/3 от всички смъртни случаи</strong>.</p><p>Клинично се проявява най-често след <strong>60-годишна възраст при мъжете</strong> и след <strong>70-годишна възраст при жените</strong>.</p><p>Основната причина за редуцираното миокардно кръвоснабдяване е <strong>коронарната атеросклероза</strong>, чиято генеза е сходна със системната атеросклероза. Главни рискови фактори са <strong>хиперлипопротеинемия, артериална хипертония, захарен диабет и тютюнопушене</strong>. Значение имат и генетични фактори, особено при наследяване на състояния като хиперхолестеролемия и диабет.</p><h2>Основни синдроми</h2><p>В зависимост от степента и разпространението на коронарната стеноза и реакцията на миокарда към кислородния недостиг се развиват четири основни синдрома:</p><ul><li><strong>ангина пекторис</strong></li><li><strong>остър миокарден инфаркт</strong></li><li><strong>хронична исхемична болест на сърцето</strong></li><li><strong>внезапна сърдечна смърт</strong></li></ul><h2>Патогенеза</h2><p>Клинично проявената ИБС е свързана с <strong>критични стенози</strong> на един или повече субепикардни стволове на коронарните артерии. Обикновено това означава редукция на лумена над <strong>75%</strong> от атеросклеротични плаки.</p><p>При такава фиксирана стеноза коронарният кръвоток не може адекватно да се увеличи дори при умерено повишаване на кислородните потребности на миокарда.</p><p>Клиничната изява и прогнозата зависят не само от хроничната стеноза, но и от <strong>остри промени в атеросклеротичната плака</strong> — кръвоизлив, ерозия, улцерация или руптура. Те могат да доведат до тромбоза върху плаката.</p><p>Тромбът превръща частичната стеноза в <strong>пълна обструкция</strong>, която може да причини исхемична некроза — <strong>миокарден инфаркт</strong>.</p><p>Допълнителна роля има <strong>коронарният спазъм</strong>, който води до преходно стеснение на лумена — т.нар. динамична оклузия. Той може да възникне при руптура на плака и тромбоцитна агрегация, поради освобождаване на вазоконстриктори като <strong>тромбоксан A₂</strong>.</p><p><strong>Ендотелната дисфункция</strong> също може да предизвика вазоспазъм поради намалена продукция на релаксиращи фактори като <strong>азотен оксид</strong>. Повишената адренергична активност, например при стрес, също може да участва в коронарния спазъм.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Ангина пекторис</h2><p><strong>Ангина пекторис</strong> е клиничен синдром на <strong>ИБС</strong>, характеризиращ се с пароксизмални пристъпи на субстернален или прекордиален дискомфорт. Причинява се от епизоди на <strong>транзиторна миокардна исхемия</strong>, продължаваща от около <strong>15 секунди до 15 минути</strong>, която е достатъчно кратка, за да не предизвика миокарден инфаркт.</p><p>Развива се при различна комбинация от <strong>повишена кислородна потребност на миокарда</strong> и <strong>намалена миокардна перфузия</strong>. Причините могат да бъдат фиксирани стенозиращи атеросклеротични плаки, руптура на плака, вазоспазъм, тромбоза или емболия.</p><h3>Стабилна ангина пекторис</h3><p>Това е най-честата форма и се нарича още <strong>типична ангина пекторис</strong>. Характеризира се с пристъпи на недобре локализиран, дълбок гръден дискомфорт, който се появява при физическо натоварване, емоционална възбуда или други състояния с повишена работа на сърцето.</p><p>Свързана е с хронична високостепенна <strong>атеросклеротична стеноза</strong> на коронарните артерии. В покой стенозираните съдове осигуряват достатъчно кръвоснабдяване, но при повишени нужди не могат да увеличат адекватно кръвотока.</p><p>Пристъпът преминава за <strong>5–15 минути</strong> след прекратяване на усилието или след прием на <strong>нитроглицерин</strong>.</p><h3>Вариантна ангина на Prinzmetal</h3><p>Това е рядка форма на епизодична ретростернална болка, която се появява <strong>в покой</strong>, понякога по време на сън.</p><p>Дължи се на <strong>спазъм на коронарните артерии</strong>, обикновено в сегмент, съседен на атеросклеротична плака. Пристъпът се повлиява бързо от вазодилататори като <strong>нитроглицерин</strong> и калциеви антагонисти.</p><h3>Нестабилна ангина</h3><p>Характеризира се с пристъпи на ретростернална болка, които настъпват при малко физическо усилие или в покой. Те продължават над <strong>20 минути</strong> и постепенно увеличават честотата и продължителността си.</p><p>Най-често се дължи на <strong>руптура на атеросклеротична плака</strong> с пристенна тромбоза и евентуален вазоспазъм. Исхемията е относително кратка, за да предизвика клинично изявен миокарден инфаркт, но нестабилната ангина често го предшества. Затова се нарича и <strong>преинфарктна ангина</strong>.</p><h3>Микроскопски</h3><p>При всички форми на ангина пекторис в миокарда могат да се открият дисеминирани дребни огнища на некроза на мускулни клетки или <strong>микроцикатрикси</strong> на мястото на предшестващи паренхимни некрози.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Миокарден инфаркт</h2><p><strong>Миокардният инфаркт (МИ)</strong> представлява участък на <strong>миокардна некроза</strong>, причинена от локална абсолютна исхемия. Той е една от основните причини за инвалидност и смърт в икономически развитите страни и стои в основата на около <strong>20–25% от всички смъртни случаи</strong>. Рискът нараства с възрастта и е <strong>3–4 пъти по-висок при мъжете</strong>.</p><h3>Видове миокарден инфаркт</h3><p>Според обхвата на некрозата в камерната стена се различават два основни типа:</p><ul><li><strong>Трансмурален инфаркт</strong> — исхемичната некроза обхваща <strong>цялата дебелина на камерната стена</strong> в зоната на кръвоснабдяване на една коронарна артерия. Обикновено е унифокален и с диаметър над <strong>2.5 cm</strong>. Около <strong>95% от смъртоносните миокардни инфаркти</strong> са трансмурални. Най-често възниква при оклузивна коронарна тромбоза върху атеросклеротична плака с остро увреждане — фисура или разязвяване.</li><li><strong>Субендокарден инфаркт</strong> — некрозата е ограничена във вътрешната третина или половина на камерната стена. Може да обхваща зона, която не съответства само на една коронарна артерия. Най-често се дължи на <strong>дифузна стенозираща атеросклероза</strong> без руптура на плака и без наслоена тромбоза. Провокира се от вазоспазъм, хипотония или повишено функционално натоварване. При тежка глобална хипотония, например при шок, субендокардният инфаркт може да обхване цялата обиколка на камерата.</li></ul><p>Двата типа са свързани, защото трансмуралният инфаркт често започва като <strong>субендокардна некроза</strong>, която постепенно обхваща цялата дебелина на стената.</p><p>Клинично по EKG миокардните инфаркти се разделят на:</p><ul><li><strong>STEMI</strong> — миокарден инфаркт с елевация на ST-сегмента, съответстващ най-често на трансмурален инфаркт;</li><li><strong>NSTEMI</strong> — миокарден инфаркт без ST-елевация, съответстващ най-често на субендокарден инфаркт.</li></ul><p><strong>STEMI</strong>, <strong>NSTEMI</strong> и <strong>нестабилната ангина</strong> се обединяват като <strong>остри коронарни синдроми</strong>, защото имат обща патогенеза.</p><h3>Патогенеза</h3><p>В около <strong>90%</strong> от случаите острият трансмурален миокарден инфаркт се причинява от <strong>оклузивна тромбоза на коронарна артерия</strong>, развиваща се върху тежка коронарна атеросклероза.</p><p>Обикновено настъпва остро увреждане на атеросклеротична плака — <strong>улцерация или фисура</strong>. Така субендотелният колаген и атероматозната материя влизат в контакт с кръвта. Това предизвиква <strong>адхезия и агрегация на тромбоцити</strong>, които освобождават тромбоксан A<sub>2</sub>, тромбоцитни фактори 3 и 4 и серотонин.</p><p>Първоначално се образува <strong>пристенен тромб</strong>, който бързо нараства и може да доведе до <strong>пълна обтурация</strong> на лумена на засегнатата коронарна артерия.</p><p>В около <strong>10%</strong> от случаите трансмурален инфаркт може да възникне без коронарна тромбоза — при интензивен и продължителен <strong>вазоспазъм</strong> или при коронарна емболия от мурални тромби в лявата сърдечна половина.</p><p>Когато кръвоснабдяването на миокарда се намали силно под неговите нужди за повече от <strong>20–40 минути</strong>, се развива трайна дълбока исхемия, загуба на функция и <strong>клетъчна смърт</strong>. Ако кръвотокът се възстанови в рамките на около <strong>20 минути</strong>, клетъчният виталитет може да се запази. Това обуславя значението на ранната диагноза и ранната терапия, включително <strong>тромболиза</strong>, за ограничаване на зоната на некроза.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778164718375-image.png &quot;width=100%&quot;)\" id=\"note-1778164719889-0\">Локализация</span></h3><p><strong>Трансмуралният миокарден инфаркт</strong> обикновено обхваща цялата зона, кръвоснабдявана от тромбозираната коронарна артерия. Затова локализацията му зависи от мястото на обтурацията.</p><ul><li>При обтурация на <strong>десцендентния клон на лявата коронарна артерия</strong> — 40–50% от случаите — исхемичната зона обхваща <strong>предната стена и върха на лявата камера</strong>, както и <strong>предните 2/3 от междукамерния септум</strong>.</li><li>При обтурация на <strong>циркумфлексния клон на лявата коронарна артерия</strong> — 15–20% — некрозата обхваща <strong>латералната стена на лявата камера</strong>.</li><li>При обтурация на <strong>дясната коронарна артерия</strong> — 30–40% — исхемичната зона е в <strong>задната стена на лявата камера</strong> и задната 1/3 от междукамерния септум.</li></ul><p>Размерът на инфаркта зависи главно от <strong>тежестта и продължителността на исхемията</strong>. Най-големият диаметър на некрозата е над <strong>2.5 cm</strong>, но може да достигне <strong>4–8 cm</strong>.</p><h3>Морфологични промени според давността на миокардния инфаркт</h3><p>Макроскопските и микроскопските прояви на <strong>миокардния инфаркт</strong> зависят от неговата давност и имат характерна последователност.</p><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Срок след началото</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Морфологични промени</span></strong></td></tr><tr><td><strong>2–12 часа</strong></td><td>Инфарктът трудно се разпознава макроскопски. <br>Микроскопски се наблюдават <strong>оток</strong> и микрокръвоизливи.</td></tr><tr><td><strong>12–24 часа</strong></td><td>Инфарктната зона става <strong>бледа и пъстра</strong>. <br>Микроскопски започва <strong>коагулационна некроза</strong> с ядрена пикноза, хипереозинофилия на миоцитите и начална неутрофилна инфилтрация.</td></tr><tr><td><strong>1-3 дни</strong></td><td>Огнището е <strong>жълтеникаво-кафяво и пъстро</strong>. <br>Микроскопски има ясна некроза с безядрени фрагментирани миоцити и обилна интерстициална инфилтрация с неутрофили.</td></tr><tr><td><strong>3–7 дни</strong></td><td>Огнището е <strong>жълтеникаво-кафяво</strong> с <strong>хиперемично-хеморагична зона</strong>. <br>Микроскопски започва разграждане на загиналите миоцити от макрофаги.</td></tr><tr><td><strong>7–10 дни</strong></td><td>Некротичното огнище е с интензивен <strong>жълто-кафеникав цвят</strong>. <br>Микроскопски се развива <strong>гранулационна тъкан</strong> на мястото на некрозата.</td></tr><tr><td><strong>2–8 седмици</strong></td><td>Макроскопски се оформя <strong>сиво-белезникав цикатрикс</strong>. <br>Микроскопски некрозата е заместена от <strong>фиброзна тъкан</strong>.</td></tr></tbody></table><blockquote><p>Миокардният инфаркт условно се разделя на две фази:</p><ul><li><strong>донекротична фаза</strong> – ранна исхемична увреда, при която още няма ясно изразена некроза при рутинно оцветяване;</li><li><strong>некротична фаза</strong> – настъпва коагулационна некроза на кардиомиоцитите.</li></ul><p><strong>Донекротичната фаза</strong> може да се докаже с <strong>оцветяване по Lie (Ли)</strong>: исхемично увредените миоцити се оцветяват <strong>червено</strong>, а запазеният миокард — <strong>жълто</strong>.</p></blockquote><h3>Прогноза</h3><p>Прогнозата зависи преди всичко от <strong>размера на инфаркта</strong>. При малки инфаркти, обхващащи под 1/3 от мускулната маса на лявата камера, прогнозата е добра. Обширните трансмурални инфаркти често се усложняват.</p><h3>Усложнения в ранната исхемична фаза</h3><ul><li><strong>Сърдечни аритмии и проводни нарушения</strong> — срещат се при 75–95% от болните и са главна причина за внезапна смърт.</li><li><strong>Остра контрактилна недостатъчност на лявата камера</strong> — при около 60% от болните, проявява се с белодробен оток, тежка диспнея и цианоза.</li><li><strong>Кардиогенен шок</strong> — най-тежката форма на контрактилна недостатъчност. Развива се при обширни инфаркти със загуба на над 40% от миокарда на лявата камера и завършва фатално в голяма част от случаите.</li></ul><h3>Усложнения в по-късния период</h3><ul><li><strong>Фибринозен перикардит</strong> (<em>pericarditis epistenocardica</em>) — развива се 2–5 дни след инфаркта и обикновено е с добра прогноза.</li><li><strong>Пристенна тромбоза</strong> в областта на некрозата — среща се при 15–40% от болните и носи риск от периферна тромбоемболия.</li><li><strong>Руптура на инфарцирания участък</strong> — най-често на 4–5-ия ден, когато некротичната зона се размеква от протеолитичните ензими на неутрофилите. Води до кръвоизлив в перикардната торбичка, <strong>сърдечна тампонада</strong> и бърза смърт.</li><li><strong>Аневризма на сърдечната камера</strong> — може да бъде остра в зоната на некрозата или хронична в областта на миокардния цикатрикс. Свързана е с риск от мурална тромбоза и периферна емболизация.</li></ul><h3>Промени в морфологията на МИ след тромболиза и коронарна ангиопластика</h3><p><strong>Тромболитичната терапия</strong> със стрептокиназа или тъканен плазминоген-активатор се прилага с цел лизиране на тромба, причинил острия миокарден инфаркт. Така се възстановява кръвотокът в зоната, застрашена от инфаркт, и се цели запазване на исхемичния, но все още жизнеспособен миокард.</p><p>Тежката миокардна исхемия не води веднага до клетъчна смърт. Загубата на миокардна виталност настъпва постепенно в рамките на няколко часа. Затова <strong>ранната реперфузия</strong> може да възстанови баланса между кислородните нужди и перфузията.</p><p>Най-важни са първите <strong>3–4 часа</strong>. Реперфузия в рамките на <strong>15–20 минути</strong> след началото на исхемията може напълно да предотврати некрозата, а при по-късно приложение — да ограничи размера ѝ.</p><p><strong>Коронарната балонна ангиопластика</strong> също се използва при остър миокарден инфаркт. Чрез балонен катетър се премахва тромботичната оклузия и се намалява стенозата от подлежащата плака. Балонът разкъсва плаката и разтяга медията, с което разширява стеснения лумен.</p><p><strong>Микроскопски</strong> реперфузираният миокарден инфаркт показва:</p><ul><li>кръвоизливи;</li><li>дисеминирани огнища от некротични миоцити;</li><li>некроза тип <strong>„контрактурни ивици“</strong>.</li></ul><p>Тези промени се дължат на увреждане на стените на малките интрамурални съдове и прогресираща дезинтеграция на миоцити, критично увредени при предшестващата исхемия.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хронична исхемична болест на сърцето</h2><p><strong>Хроничната исхемична болест на сърцето (хрИБС)</strong> представлява бавно прогресираща <strong>сърдечна недостатъчност</strong>, развиваща се вследствие на продължително исхемично увреждане на миокарда. Често има анамнеза за дългогодишна <strong>ангина пекторис</strong> или прекаран <strong>миокарден инфаркт</strong>. В клиниката се използва и терминът <strong>исхемична кардиомиопатия</strong>.</p><p><strong>Макроскопски:</strong> сърцето обикновено е уголемено поради <strong>хипертрофия и дилатация на лявата камера</strong>. Винаги се установява умерена до тежка <strong>стенозираща атеросклероза</strong> на коронарните артерии.</p><p><strong>Микроскопски:</strong> наблюдават се дифузна атрофия на миоцитите, <strong>интерстициална фиброза</strong> и дребноогнищна заместителна фиброза. При преживян миокарден инфаркт се откриват и големи <strong>постинфарктни цикатрикси</strong>.</p><p><strong>Еволюция:</strong> заболяването прогресира бавно, в продължение на години, и се проявява със сърдечна недостатъчност. Смърт може да настъпи поради прогресираща СН, остър миокарден инфаркт или фатална аритмия. Възможно е хрИБС да протича безсимптомно и да се открие случайно.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Внезапна сърдечна смърт</h2><p><strong>Внезапната сърдечна смърт</strong> е неочаквана смърт, настъпваща в рамките на <strong>първия час</strong> след началото на клиничните прояви.</p><p>Най-честата причина е <strong>исхемична болест на сърцето</strong>, макар че може да настъпи и при други сърдечни заболявания.</p><p>В основата ѝ в <strong>75–95%</strong> от случаите стои високостепенна <strong>коронарна стеноза</strong> — над 75% от съдовия лумен — на една или повече коронарни артерии, често с остри увреждания на атеросклеротичните плаки. В около <strong>1/3</strong> от случаите се открива коронарна тромбоза, понякога съчетана с остър миокарден инфаркт.</p><p>Непосредствената причина за смъртта е <strong>фатална сърдечна аритмия</strong> — най-често камерна фибрилация или асистолия.</p><p>Исхемията уврежда клетъчните мембрани и причинява остро преразпределение на <strong>K⁺, Ca²⁺ и Na⁺</strong> между кардиомиоцитите и екстрацелуларната течност. Така възниква <strong>електролитен дисбаланс</strong>, който води до електрична нестабилност на миокарда.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 26. Мозъчно-съдова болест – видове, морфологична характеристика.</h1><p>Начало.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 27. Ендокардити – видове. Придобити клапни пороци – морфологична характеристика. Ревматичен ендокардит.</h1><p>Нормалната функция на сърдечните клапи е да осигуряват свободен и <strong>еднопосочен кръвоток</strong> — от предсърдията към камерите и от камерите към аортата и белодробната артерия. Те не позволяват ретрограден ток на кръвта след сърдечна контракция.</p><p>Болестните увреждания на клапите водят до <strong>стеноза</strong>, <strong>инсуфициенция</strong> или комбинация от двете.</p><h3>Клапна стеноза</h3><p>При <strong>клапна стеноза</strong> клапните платна са задебелени, срастнали помежду си и не могат да се отварят напълно. Това създава пречка за преминаването на кръвта от предсърдията към камерите или от камерите към изходните магистрали.</p><h3>Клапна инсуфициенция</h3><p>При <strong>клапна инсуфициенция</strong> деформираните клапни платна не могат да се затварят плътно. В резултат се допуска <strong>регургитация</strong> — връщане на кръв от камерите към предсърдията или от аортата/белодробната артерия към камерите.</p><p>Клапните увреждания могат да бъдат <strong>изолирани</strong>, когато има само стеноза или само инсуфициенция, или <strong>комбинирани</strong>, когато едновременно са налице стеноза и инсуфициенция на една клапа.</p><h3>Функционална клапна недостатъчност</h3><p><strong>Функционална клапна недостатъчност</strong> се развива при дилатация на камерата. Тогава папиларните мускули се изместват надолу и настрани, което пречи на плътното затваряне на иначе непроменени клапни платна.</p><h3>Етиология</h3><p>Най-честите причини за клапни пороци са <strong>ревматична болест на сърцето</strong>, миксоматозна дегенерация на митралната клапа, калцификация на аортната клапа и <strong>инфекциозен ендокардит</strong>.</p><h3>Функционална морфология</h3><p>Деформираните клапни платна причиняват заболяване по два основни механизма:</p><ul><li>чрез <strong>повишено хемодинамично натоварване</strong> на сърдечните кухини поради нарушена клапна функция;</li><li>чрез повишена податливост към инфекции, което предразполага към <strong>инфекциозен ендокардит</strong> и неговите усложнения.</li></ul><p>Аномалиите на кръвния ток при клапни пороци предизвикват патологични сърдечни звуци — <strong>сърдечни шумове</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Митрални пороци</h2><p>Митралните пороци включват <strong>митрална стеноза</strong> и <strong>митрална инсуфициенция</strong>. Най-честата причина за <strong>митрална стеноза</strong> е ревматизмът, а за <strong>митрална инсуфициенция</strong> — миксоматозната дегенерация с пролапс на митралната клапа.</p><h3>Митрална стеноза</h3><p>Митралната стеноза се среща по-често при жени. При нея клапните платна и <strong>chordae tendineae</strong> са дифузно задебелени и срастнали по ръбовете и комисурите.</p><p>Митралното отвърстие е силно стеснено, а клапната деформация има вид на фуния с тесен отвор към камерата — т.нар. <strong>„уста на риба“</strong>.</p><p>Затрудненото преминаване на кръвта през стенозираната митрална клапа води до <strong>хипертрофия и дилатация на лявото предсърдие</strong>. Ендокардът се задебелява и става неравен, което благоприятства образуването на <strong>мурална тромбоза</strong>. Тези тромби могат да бъдат източник на емболи в големия кръг на кръвообращението.</p><p>Понякога откъснати тромбни фрагменти остават в лявото предсърдие, защото са по-големи от стенозираното митрално отвърстие. Постоянно обмивани от кръвта, те нарастват и се превръщат в <strong>кръгли тромби</strong>, които могат внезапно да запушат митралното отвърстие и да доведат до смърт.</p><p>Продължителната задръжка на кръв в лявото предсърдие се предава към белодробните вени и белите дробове. Развиват се <strong>хроничен венозен застой</strong> и <strong>кафява индурация на белите дробове</strong>. Последващата белодробна хипертония натоварва дясната сърдечна половина, която хипертрофира, дилатира и декомпенсира.</p><p>При изолирана чиста митрална стеноза <strong>лявата камера остава непроменена</strong>. Характерният вид на сърцето — торбовидно разширено ляво предсърдие с хипертрофия и дилатация на дясната половина — се означава като <strong>„митрална конфигурация“</strong>.</p><h3>Митрална инсуфициенция</h3><p>При митрална инсуфициенция клапните платна са <strong>задебелени, сгърчени и скъсени</strong>, поради което не се затварят плътно. Това води до <strong>регургитация</strong> — връщане на кръв от лявата камера към лявото предсърдие по време на камерната систола.</p><p>Допълнителният обем кръв в лявото предсърдие преминава обратно в лявата камера по време на диастолата. Така се развива <strong>обемно натоварване</strong>, което постепенно води до <strong>хипертрофия и дилатация</strong> както на лявото предсърдие, така и на лявата камера.</p><p>Много често митралната инсуфициенция е комбинирана със стеноза, като може да преобладава едната или другата компонента.</p><p>При продължителни хемодинамични нарушения се развиват <strong>кафява индурация на белите дробове</strong>, прогресивно натоварване на дясната сърдечна половина, нейна хипертрофия и дилатация, а по-късно и венозен застой в големия кръг.</p><h3>Пролапс на митралната клапа</h3><p><strong>Синоним:</strong> миксоматозна дегенерация на митралната клапа.</p><p>Пролапсът на митралната клапа е клапна лезия, която може да доведе до <strong>митрална инсуфициенция</strong>. Среща се най-често при млади жени, често протича безсимптомно и се открива случайно по наличие на <strong>систоличен шум</strong>.</p><p><strong>Макроскопски</strong> клапните платна са уголемени, млечно-белезникави, задебелени, но мековати и отпуснати. <strong>Chordae tendineae</strong> са удължени, което води до характерното <strong>балоновидно издуване</strong> на клапните платна към лявото предсърдие по време на систола.</p><p><strong>Микроскопски</strong> в основата стои натрупване на мукополизахаридно, базофилно „основно“ вещество в съединителнотъканния матрикс на клапните платна и chordae tendineae. При специални оцветявания това се проявява с <strong><span class=\"editor-note\" data-note=\"Хистологичен срез, показващ **миксоматозна дегенерация на митралната клапа**. Наблюдава се увеличение на **протеогликаните** и последваща **фиброза** (*) в клапната тъкан, подчертани в синьо чрез оцветяване с **трихром на Masson**. В този срез се вижда и мускулната тъкан, оцветена в червено, на миокарда на лявото предсърдие (**LA**) и лявата камера (**LV**). Виждат се също и **chordae tendineae (CT)**.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778166435403-image.png &quot;width=100%&quot;)\" id=\"note-1778166460749-1\">метахромазия</span></strong>. Натрупването отслабва фиброзния скелет на клапата.</p><p>Пролапсът може да бъде изолирана митрална лезия или проява на <strong>синдром на Marfan</strong> и други заболявания на съединителната тъкан. Подобни промени по-рядко могат да засегнат трикуспидалната, аортната и пулмоналната клапа.</p><p>Обикновено е асимптоматичен, но в малък процент от случаите може да причини значима <strong>митрална инсуфициенция</strong> и сърдечна недостатъчност.</p><p><strong>Усложнения:</strong> инфекциозен ендокардит, емболизация от тромботични отлагания, камерни и предсърдни аритмии и внезапна смърт.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Аортни пороци</h2><p>Аортните пороци най-често са резултат от <strong>хроничен ревматичен аортен валвулит</strong> и се срещат по-често при мъже. Чистите форми на аортна стеноза или аортна инсуфициенция са редки; обикновено пороците са <strong>комбинирани</strong>, с преобладаване на стенотична или инсуфициентна компонента.</p><p>Най-чести причини:</p><ul><li><strong>аортна стеноза</strong> – калцификация на анатомично нормална или вродена бикуспидална аортна клапа;</li><li><strong>аортна инсуфициенция</strong> – дилатация на асцендентната аорта, често свързана с хипертония и стареене.</li></ul><h3>Аортна стеноза</h3><p>Аортната стеноза може да бъде резултат от <strong>ревматичен валвулит</strong> или от <strong>дегенеративна калцификация</strong> на аортната клапа. При ревматичната форма има сливане на комисурите, докато при дегенеративната калцификатна стеноза <strong>комисурите не са сраснали</strong>.</p><h4>Ревматична аортна стеноза</h4><p>Клапните платна са силно задебелени, плътни и срастнали в комисурите. Формира се ригиден триъгълен клапен отвор, сравняван с емблемата на <strong>„Мерцедес“</strong>. Намаляването на клапното отвърстие увеличава съпротивлението срещу изтласкването на кръвта в аортата, което води до <strong>левокамерна хипертрофия</strong>.</p><h4>Дегенеративна калцификатна стеноза на аортната клапа</h4><p>Наблюдава се най-често след <strong>70-годишна възраст</strong> и затова се нарича още <strong>сенилна калцификатна аортна стеноза</strong>.</p><p>Характеризира се с <strong>фиброза и обилна калцификация</strong> на аортните клапни платна. Те са силно задебелени, ригидни, грубо неравни и с намалена или липсваща подвижност. Калцификатите могат да проминират към <strong>синусите на Valsalva</strong> и аортния остиум, причинявайки различна по степен стеноза.</p><p>Обилни калциеви отлагания могат да се развият и при вродени аномалии на аортната клапа — <strong>бикуспидна</strong> или <strong>монокуспидна клапа</strong>.</p><p>Клиничните прояви зависят от степента на стенозата. Високостепенната стеноза води до <strong>повишено тенсионно натоварване</strong>, <strong>левокамерна хипертрофия</strong> и в късните стадии — <strong>сърдечна недостатъчност</strong>.</p><p>Чести усложнения са <strong>ангина пекторис</strong>, камерни и предсърдни аритмии, инфекциозен ендокардит и тромбоемболии.</p><h3>Аортна инсуфициенция</h3><p>При преобладаваща ревматична <strong>аортна инсуфициенция</strong> клапните платна са фиброзирани, деформирани, срастнали в комисурите и ретрахирани към аортната стена. Това пречи на плътното им затваряне.</p><p>В резултат част от кръвта се връща от аортата към <strong>лявата камера</strong> по време на диастола. Повишеното обемно натоварване води първоначално до <strong>хипертрофия</strong>, а по-късно и до <strong>дилатация</strong> на лявата камера.</p><p>Крайният изход е <strong>левостранна сърдечна недостатъчност</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Ревматичен ендокардит</h2><p><strong>Ревматичният ендокардит</strong> е най-манифестната проява на ревматичната болест на сърцето. Засяга главно клапните платна — <strong>ревматичен валвулит</strong>, и може да доведе до трайни клапни деформации.</p><p>Различават се <strong>4 форми на ревматичен ендокардит</strong>:</p><ul><li><strong>дифузен ендокардит</strong></li><li><strong>остър верукозен ендокардит</strong></li><li><strong>фиброзен ендокардит</strong></li><li><strong>рецидивиращ верукозен ендокардит</strong></li></ul><p>Най-често се увреждат клапите на лявата сърдечна половина:</p><ul><li><strong>митрална клапа</strong> — изолирано в 65–70% от случаите;</li><li><strong>митрална + аортна клапа</strong> — в 20–25%;</li><li><strong>аортна клапа</strong> — изолирано в 15–20%.</li></ul><p>Трикуспидалната и белодробната клапа се засягат по изключение.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778167788478-image.png &quot;width=100%&quot;)\" id=\"note-1778167789917-7\">Макроскопски</span></h3><p>Засегнатите клапни платна са <strong>зачервени, оточни и задебелени</strong>.</p><p>По предсърдната повърхност на митралната клапа и камерната повърхност на аортната клапа, най-вече по клапните ръбове, се виждат множество дребни <strong>сиво-розови възелчета</strong> с размер 1–2 mm.</p><p>Те се наричат <strong>веруки / брадавици</strong> и са подредени в редица като „зърна на броеница“. Плътно са прикрепени към подлежащата тъкан. Тази картина се означава като <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778166848278-image.png &quot;width=100%&quot;)\" id=\"note-1778166850274-2\">ревматичен верукозен ендокардит</span></strong>.</p><h3>Микроскопски</h3><p><strong>Верките</strong> са изградени от <strong>тромбоцитни агрегати и фибрин</strong> и не съдържат микроорганизми, което ги отличава от вегетациите при инфекциозен ендокардит.</p><p>В подлежащата спонгиозна тъкан на клапата се наблюдава инфилтрация от <strong>мононуклеарни левкоцити</strong>, а рядко — абортивни <strong>грануломи на Ашоф</strong>.</p><p>Характерен белег на ревматичния валвулит е появата на <strong>капиляри и артериоли в клапните платна</strong>, които нормално са аваскуларни.</p><h3>Изход</h3><p>Острите възпалителни изменения могат да отзвучат напълно, но по-често тромботичните вегетации се <strong>организират</strong> и се заместват от фиброзна тъкан.</p><p>Това води до:</p><ul><li>склеротично уплътняване и задебеляване на клапните платна;</li><li>срастване по ръбовете;</li><li>трайни клапни деформации.</li></ul><p>Обилната васкуларизация на засегнатите клапи е важен микроскопски белег за <strong>постревматична природа</strong> на клапния порок.</p><p>При хронифициране се развива <strong>фиброзен ендокардит</strong>. Най-характерно е засягането на митралната клапа, при което срастването на комисурите и деформацията на клапните платна водят до стеноза с типичен макроскопски вид на <strong>„<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778166888006-image.png &quot;width=100%&quot;)\" id=\"note-1778166889450-3\">уста на риба</span>“</strong>.</p><p>Обилната васкуларизация на засегнатите клапи е важен микроскопски белег за постревматична природа на клапния порок.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Небактериален тромботичен ендокардит</h2><p><strong>Небактериалният тромботичен ендокардит</strong> е форма на <strong>верукозен ендокардит</strong>, който се среща при изтощени болни с напреднали злокачествени тумори или сепсис. Затова се нарича още <strong>марантичен ендокардит</strong>.</p><p>Често се развива едновременно с <strong>венозни тромбози</strong> или <strong>белодробна тромбоемболия</strong>. Смята се, че общият механизъм е <strong>хиперкоагулабилност</strong>, обусловена от системна активация на кръвосъсирването. Такава може да се наблюдава например при карцином на стомашно-чревния тракт или яйчниците.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778167766871-image.png &quot;width=100%&quot;)\" id=\"note-1778167768031-6\">Макроскопски</span></h3><p><strong style=\"color: rgb(31, 41, 55)\">Макроскопски при NBTE</strong><span style=\"color: rgb(31, 41, 55)\"> се виждат малки или средни </span><strong style=\"color: rgb(31, 41, 55)\">стерилни тромботични вегетации</strong><span style=\"color: rgb(31, 41, 55)\">, обикновено прикрепени по линията на затваряне на клапните платна, без значимо възпаление или клапна деструкция.</span></p><h3>Микроскопски</h3><p>Характеризира се с отлагане на малки <strong>стерилни вегетации</strong> с размер <strong>1–5 mm</strong>, изградени от <strong>фибрин и кръвни клетки</strong>. Те се разполагат върху <strong>неувредени клапи</strong> на едната или другата сърдечна половина.</p><p>За разлика от инфекциозния ендокардит:</p><ul><li>вегетациите <strong>не съдържат микроорганизми</strong>;</li><li>не предизвикват възпалителна реакция в подлежащата клапна тъкан;</li><li>не се организират;</li><li>не водят до клапна деформация.</li></ul><h3>Усложнения</h3><p>Клинично значение има рискът от <strong>емболии</strong>. Откъснати фрагменти от вегетациите могат да причинят инфаркти в <strong>главния мозък, сърцето</strong> или други органи.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Протезен ендокардит</h2><p><strong>Усложнения на клапното протезиране</strong></p><p>Клапните протези се използват за корекция на клапни пороци и са два основни типа:</p><ul><li><strong>механични протези</strong> — с различни устройства за затваряне на клапното отвърстие;</li><li><strong>биологични протези</strong> — изградени от животинска тъкан, най-често свински клапни платна, фиксирани в глутаралдехид и монтирани върху протезна рамка.</li></ul><p>Усложненията на клапното протезиране са относително чести и се развиват при значителна част от болните до 10 години след операцията.</p><h3>Тромбоемболични усложнения</h3><p>Това е основен проблем при <strong>механичните протези</strong>. Може да настъпи локална тромбозна оклузия на протезата или дистантна тромбоемболия.</p><p>Поради това пациентите с механични клапи се нуждаят от продължителна <strong>антикоагулантна терапия</strong>. Като усложнение от нея могат да настъпят кръвоизливи, включително мозъчни и стомашно-чревни.</p><h3>Дехисценция на шевовете</h3><p>Представлява частично разкъсване или отпускане на шевовете, които фиксират протезата. Най-често възниква при <strong>протезен ендокардит</strong> и може да доведе до образуване на <strong>паравалвуларна цепнатина</strong>.</p><h3>Инфекциозен протезен ендокардит</h3><p>Развива се при част от пациентите след клапно протезиране и може да засегне както механични, така и биологични протези.</p><p>Възпалението се локализира в зоната на контакт между протезата и тъканта, като може да доведе до <strong>ануларен абсцес</strong>. При персистиране на процеса се развива <strong>паравалвуларна перфорация</strong>, която причинява регургитация на кръв. В тежки случаи може да настъпи <strong>дислокация на протезата</strong>.</p><p>Най-чести причинители са <strong>Staphylococcus aureus</strong> и <strong>Staphylococcus epidermidis</strong> в ранния постоперативен период, а по-късно — стрептококи.</p><h3>Структурни увреждания на протезата</h3><p>При механичните протези са редки. При <strong>биологичните протези</strong> по-често се наблюдава прогресиращо <strong>вкалцяване на клапните платна</strong>.</p><p>В рамките на 10 години част от тъканните клапи се увреждат до степен, че се налага замяна с нова протеза.</p><blockquote>+ инфекциозен ендокардит, но то е следващата тема. + може би ендокардит при <span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778167802449-image.png &quot;width=100%&quot;)\" id=\"note-1778167805725-8\">СЛЕ</span>?</blockquote><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 28. Инфекциозен ендокардит – видове, морфологична характеристика.</h1><p><strong>Инфекциозният ендокардит (ИЕ)</strong> се причинява от инвазия на микробни агенти в сърдечните клапи — интактни или вече болестно променени — около клапни протези или в муралния ендокард.</p><p>Характерната лезия са <strong>вегетациите</strong> — обемисти, трошливи тромботични наслоения, инфектирани с микроорганизми. Най-чести причинители са <strong>бактерии</strong>, но етиологична роля могат да имат и гъби, рикетсии (Q-треска) и хламидии.</p><h2>Форми</h2><p>Според клиничното протичане ИЕ се разделя на <strong>остър</strong> и <strong>подостър</strong>, като разликата зависи главно от вирулентността на причинителя и наличието на предшестващо сърдечно заболяване.</p><h3>Остър инфекциозен ендокардит</h3><p>Представлява <strong>деструктивна инфекция на интактни клапни платна</strong> от високовирулентни микроорганизми. Протича фулминантно, с висока температура и картина на <strong>сепсис</strong>. В рамките на дни до седмици може да доведе до смърт при &gt;50 % от болните, въпреки антибиотична терапия или хирургична намеса.</p><h3>Подостър инфекциозен ендокардит</h3><p>Причинява се от условно патогенни микроорганизми с по-слаба вирулентност. Те обикновено инфектират <strong>деформирани клапни платна</strong> или <strong>аномални сърдечни структури</strong>, например вродени септални дефекти.</p><p>Заболяването се развива подмолно, с отпадналост и неспецифична симптоматика. Протича седмици до месеци, но при подходяща терапия пациентите могат да се възстановят.</p><h2>Етиология и патогенеза</h2><p>В развитието на ИЕ участват три групи фактори:</p><ul><li><strong>бактериемия или септицемия</strong>;</li><li><strong>аномалии на клапите и сърдечните структури</strong>;</li><li><strong>нарушена защита на организма</strong>.</li></ul><p>Епизодите на бактериемия са основна предпоставка за заселване на микроорганизми в ендокарда. При високовирулентни пиогенни коки, като <strong>Staphylococcus aureus</strong>, <strong>пневмококи </strong>и <strong>гонококи</strong>, могат да се атакуват и интактни клапи, което води до остър ИЕ.</p><p>По-често ИЕ се причинява от по-слабо вирулентни микроорганизми като <strong>Streptococcus viridans</strong>, <strong>Streptococcus faecalis</strong> и <strong>Escherichia coli</strong>, които навлизат в кръвта при зъбни екстракции, катетеризации или хирургични интервенции. Те обикновено инфектират предварително увредени клапи и водят до подостър ИЕ.</p><p>Деформираните клапни платна с неравна повърхност и ендотелни лезии улесняват отлагането на тромбоцити и фибрин. Така се образуват малки стерилни тромби, които при бактериемия стават място за залавяне на микроорганизмите. В тромба те се предпазват от фагоцитоза, размножават се и проникват в подлежащата клапна тъкан.</p><p>Предразполагащи фактори са <strong>имуносупресия</strong>, неутропения, недоимъчно хранене, хроничен алкохолизъм и др.</p><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778167679655-image.png &quot;width=100%&quot;)\" id=\"note-1778167681535-5\">Макроскопски</span></h2><p>Патогномонични за ИЕ са <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778167665661-image.png &quot;width=100%&quot;)\" id=\"note-1778167667475-4\">вегетациите</span></strong> — големи тромботични маси, обикновено <strong>0.5–2 cm</strong>, които са инвазирани от микробни причинители и провисват като полипи от клапните платна.</p><p>Най-често се засягат <strong>аортната</strong> и <strong>митралната клапа</strong>. При интравенозни наркомани често може да се засегне <strong>трикуспидалната клапа</strong>, тъй като инфекцията се внася директно във венозната кръв чрез замърсени игли и спринцовки.</p><p>При <strong>острия ИЕ</strong> вегетациите са особено големи, а под тях се намира деструкция на клапните платна — <strong>улцерация</strong>, понякога и руптура. Тази картина се означава като <strong>улцеро-полипозен ендокардит</strong>.</p><p>При <strong>подострия ИЕ</strong> вегетациите са по-малки и по-рядко причиняват ерозия или перфорация на клапата.</p><h2>Микроскопски</h2><p>Вегетациите са изградени от <strong>фибрин, тромбоцити и кръвни клетки</strong>, сред които се намират колонии от микроорганизми.</p><p>Подлежащата клапна тъкан е васкуларизирана и плътно инфилтрирана с левкоцити, главно <strong>неутрофили</strong>.</p><p>При подострия ИЕ вегетациите имат <strong>гранулационна тъкан</strong> в основата си и с времето фиброзират.</p><h2>Усложнения</h2><ul><li><strong>Сърдечни усложнения:</strong> възможна е перфорация на клапно платно с остра клапна инсуфициенция. Може да настъпи и ерозия на подлежащия миокард с образуване на <strong>ring abscess</strong>-на кухина, която понякога перфорира към междукамерната преграда.</li><li><strong>Тромбоемболии:</strong> вегетациите са трошливи и слабо прикрепени, затова лесно дават емболи в системната циркулация. Развиват се инфаркти в главния мозък, миокарда, слезката и други органи.</li><li>При остър ИЕ емболите съдържат вирулентни микроорганизми и инфарктите могат да супурират — образуват се <strong>септични инфаркти и абсцеси</strong>. При подостър ИЕ инфарктите обикновено не супурират.</li><li><strong>Бъбречни усложнения:</strong> могат да се развият огнищен или дифузен <strong>гломерулонефрит</strong> с имунна генеза.</li><li>Характерна е и изразена <strong>спленомегалия</strong>, особено при подострия ИЕ.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 29. Миокардити – етиология, видове, морфологична характеристика.</h1><p><strong>Миокардитите</strong> се характеризират с възпалителни инфилтрати в миокарда, които увреждат съседните кардиомиоцити и водят до <strong>дегенерация или некроза</strong>.</p><h2>Етиология</h2><p>Най-често миокардитът се причинява от <strong>инфекциозни агенти</strong>, но може да бъде и резултат от <strong>имунно увреждане</strong>.</p><ul><li><strong>Инфекциозни миокардити</strong> – най-често са вирусни. Основни причинители са <strong>Coxsackie вируси</strong>, <strong>ECHO-вируси</strong> и грипни вируси. По-рядко участват цитомегаловирусът и <strong>HIV</strong>. Сърдечното увреждане се проявява дни до седмици след първична вирусна инфекция.</li><li><strong>Бактериални миокардити</strong> – по-редки, развиват се при тежки бактериални инфекции, най-често с пиогенни коки, достигащи миокарда по хематогенен път. <strong>Дифтерийният миокардит</strong> се дължи не на директна инвазия, а на действието на <strong>дифтерийния екзотоксин</strong>.</li><li><strong>Неинфекциозни / имунни миокардити</strong> – наблюдават се при <strong>остър ревматизъм</strong>, системен лупус еритематодес и хиперергични реакции към медикаменти — антибиотици, антихипертензивни средства, диуретици, барбитурати.</li><li><strong>С неизвестна етиология</strong> – например <strong>гигантоклетъчен миокардит</strong> и <strong>миокардит на Fiedler</strong>.</li></ul><h2>Макроскопски</h2><p>В острата фаза камерният миокард е <strong>отпуснат</strong>, а четирите сърдечни кухини са <strong>дилатирани</strong>.</p><h2>Микроскопски</h2><p>Наблюдават се интерстициални инфилтрати от <strong>лимфоцити и макрофаги</strong>, както и некроза на съседни миоцити. При оздравяване лимфоцитните инфилтрати намаляват, а на мястото на загиналите миоцити се развива <strong>фиброзна тъкан</strong>.</p><p>При отделните форми:</p><ul><li><strong>Бактериален миокардит:</strong> инфилтрати от сегментоядрени левкоцити, често с формиране на <strong>микроабсцеси</strong>.</li><li><strong>Дифтериен миокардит:</strong> обширна мастна дегенерация на миоцитите и <strong>миоцитолиза</strong>, по-късно с оскъдна лимфоцитна инфилтрация.</li><li><strong>Хиперергичен миокардит:</strong> инфилтрати от лимфоцити, макрофаги и много <strong>еозинофили</strong>.</li><li><strong>Fiedler-ов и идиопатичен гигантоклетъчен миокардит:</strong> огнищни некрози на кардиомиоцитите и грануломатозна възпалителна реакция с <strong>гигантски клетки</strong>.</li></ul><h2>Клинично протичане</h2><p>Миокардитът може да се срещне във всяка възраст. Протичането варира от безсимптомно до остро, с <strong>аритмии</strong>, сърдечна недостатъчност и дори внезапна сърдечна смърт.</p><p>Повечето болни оздравяват напълно, но в някои случаи години по-късно може да се развие <strong>дилатативна кардиомиопатия</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 30. Перикардити – етиология, класификация, морфологична характеристика.</h1><p><strong>Първичните перикардити</strong> са редки и обикновено инфекциозни — най-често вирусни, по-рядко бактериални или гъбични.</p><p>По-често перикардитите са <strong>вторични</strong>, свързани с миокарден инфаркт, сърдечни операции или системни заболявания като <strong>уремия</strong>, остър ревматизъм и системен лупус еритематодес.</p><p>Перикардитът може да протече <strong>остро</strong> или <strong>хронично</strong>. Възможно е да оздравее без значителни последици или да завърши с организация на ексудата и <strong>перикардни сраствания</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Остри перикардити</h2><p>Според характера на ексудата острите перикардити биват <strong>серозни</strong>, <strong>фибринозни</strong> и <strong>серофибринозни</strong>.</p><p><strong>Остър серозен перикардит</strong> се развива най-често при вирусни инфекции — Coxsackie, ECHO и др. Ексудатът обикновено не е обилен и рядко надхвърля <strong>200 ml</strong>. Микроскопски има слаба възпалителна инфилтрация по епикардната повърхност от <strong>лимфоцити и макрофаги</strong>. Ексудатът обикновено се резорбира напълно и сраствания се наблюдават рядко.</p><p><strong>Фибринозният и серофибринозният перикардит</strong> са най-честите форми. Срещат се след открити сърдечни операции, при <strong>миокарден инфаркт</strong>, синдром на Dressler, уремия, остър ревматизъм, системен лупус еритематодес и травма.</p><p>Макроскопски двата листа на перикарда са покрити със сивобелезникав дребнозърнист налеп от <strong>фибрин</strong>. При сърдечните контракции между тях се образуват фибринни „мостчета“, което дава картината на <strong>„влакнесто сърце“ (cor villosum)</strong> и причинява <strong>перикардно триене</strong>.<br>При серофибринозните форми течната част на ексудата е жълтеникава и мътна поради наличие на левкоцити и фибрин. Ексудатът може да се лизира и резорбира, но често се организира и води до <strong>фиброзни сраствания</strong> между перикардните листове.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хроничен перикардит</h2><p>Хроничният перикардит се развива при организация на фибринозния ексудат след остър перикардит. Може да бъде <strong>ограничен</strong>, обикновено след епистенокарден перикардит, или <strong>дифузен</strong> след разпространен остър перикардит.</p><p><strong>Макроскопски</strong> при дифузната форма сърцето е обвито от плътна, белезникава и жилава съединителна тъкан. Перикардните листове са срастнали помежду си и с подлежащия миокард. Тази картина се означава като <strong>„бронирано сърце“</strong>.</p><h3>Усложнения</h3><p>Хроничният перикардит може да доведе до <strong>тотална сърдечна недостатъчност</strong>. Причината е затруднено вливане на венозна кръв в сърцето поради притискане на венозните съдове и предсърдията от плътните фиброзни сраствания между перикарда, епикарда и миокарда.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 31. Ревматизъм. Клинико-анатомични форми, морфологична характеристика.</h1><h2>Остра ревматична болест на сърцето</h2><h3>Обща характеристика</h3><p><strong>Острият ревматизъм (ОР)</strong> е мултиорганно рецидивиращо заболяване, което се развива <strong>2–4 седмици</strong> след инфекция с <strong>β-хемолитични стрептококи от група А</strong>. Във възпалителните огнища не се откриват бактерии, затова заболяването се разглежда като <strong>имунна реакция</strong>, индуцирана от стрептококи.</p><p>Заболяването започва остро след прекаран стрептококов фарингит или тонзилит и има склонност към рецидиви. Повторни стрептококови инфекции могат да доведат до нови пристъпи.</p><h3>Органни прояви</h3><p>Острият ревматизъм се характеризира със засягане на много органи:</p><ul><li><strong>мигриращ полиартрит</strong> на големите стави;</li><li><strong>ревматичен панкардит</strong> — ревматична болест на сърцето;</li><li>кожен макуло-папулозен обрив — <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778168114734-image.png &quot;width=100%&quot;)\" id=\"note-1778168104612-9\">erythema marginatum</span></strong>, с подкожни възли;</li><li>ревматични лезии в главния мозък — <strong>chorea minor</strong>, с бързи, неволеви и безцелни движения;</li><li><strong>ревматични артериити</strong>, засягащи коронарни, бъбречни и мозъчни артерии.</li></ul><p>Най-голямото значение на ОР е свързано със <strong>сърдечните увреждания</strong>, тъй като ревматичните клапни лезии често водят до трайна клапна деформация, клапна дисфункция и по-късна сърдечна недостатъчност.</p><p>ОР може да се срещне във всяка възраст, но около <strong>90% от болните са деца между 5 и 15 години</strong>. Честотата е намаляла значително в развитите страни поради по-добри условия на живот, ранна диагноза и антибиотично лечение.</p><h3>Патогенеза</h3><p>Механизмите на тъканното увреждане не са напълно изяснени. Развитието на болестта <strong>2–4 седмици след стрептококова инфекция</strong> и липсата на бактерии в тъканните лезии подкрепят тезата за <strong>хиперергична имунна реакция</strong> към стрептококови антигени.</p><p>При около <strong>95%</strong> от болните се откриват повишени титри на специфични антитела срещу стрептококови антигени — срещу <strong>М-протеин</strong>, <strong>стрептолизин O</strong> и <strong>ДНК-аза</strong>.</p><p>Приема се, че тези антитела реагират кръстосано със собствени тъканни компоненти, антигенно сходни със стрептококите: глюкопротеини на сърдечните клапи и ставните капсули, сарколема на миокардни и гладкомускулни клетки, сърдечен миозин и др.</p><h3>Микроскопски</h3><p>При ОР в засегнатите органи се откриват <strong>дифузни и грануломатозни възпалителни инфилтрати</strong>.</p><p>Главната и патогномонична морфологична проява са <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778168466961-image.png &quot;width=100%&quot;)\" id=\"note-1778168432541-12\">грануломите на Ашоф (Aschoff)</span></strong>. Те представляват огнища на <strong>фибриноидна некроза</strong>, заобиколени от <strong>Т-лимфоцити</strong>, единични плазматични клетки и големи активирани макрофаги — <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778168544556-image.png &quot;width=100%&quot;)\" id=\"note-1778168546860-13\">клетки на Аничков</span></strong>.</p><p>Клетките на Аничков имат обилна цитоплазма и кръгли ядра с централно разположен хроматин, който е нагънат като вълнообразна ивица и наподобява <strong>„<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778168384057-image.png &quot;width=100%&quot;)\" id=\"note-1778168385483-11\">гъсеница</span>“</strong>.</p><p>В периферията на гранулома част от клетките са многоядрени — <strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778168580129-image.png &quot;width=100%&quot;)\" id=\"note-1778168581210-14\">гигантски клетки на Ашоф</span></strong>. При тях хроматинът се натрупва по ядрената мембрана и ядрото наподобява <strong>„око на кукумявка“</strong>.</p><p>Грануломите на Ашоф започват развитието си около <strong>4-тата седмица</strong> от началото на ревматичния пристъп. Постепенно броят на гигантските клетки намалява и към края на <strong>3-тия месец</strong> грануломите се заместват от дребни <strong>фиброзни цикатрикси</strong>.</p><p>Съвременната терапия, особено кортикостероидите, потиска ексудативните процеси и типичните грануломи се срещат по-рядко. В много случаи се откриват само огнищни <strong>лимфо-хистиоцитни инфилтрати</strong>, рядко с гигантски клетки.</p><h3>Морфологични форми</h3><p>При острата ревматична болест на сърцето се наблюдават <strong>ревматичен перикардит</strong>, <strong>ревматичен миокардит</strong> и <strong>ревматичен ендокардит</strong>. При засягане и на трите слоя на сърцето се говори за <strong>ревматичен панкардит</strong>.</p><h4>Ревматичен перикардит</h4><p>Ревматичният перикардит е <strong>серозен или серо-фибринозен</strong>. Грануломи на <strong>Ашоф</strong> могат да се открият в субепикардната мастна и фиброзна тъкан.</p><p>Обикновено оздравява бързо и напълно.</p><h4>Ревматичен миокардит</h4><p>Характеризира се с наличие на дисеминирани <strong>грануломи на Ашоф</strong> в интерстициалната съединителна тъкан на миокарда. Най-често са разположени <strong>периваскуларно</strong>.</p><p>С течение на времето грануломите се заместват от <strong>поствъзпалителни цикатрикси</strong>.</p><h4><span class=\"editor-note\" data-note=\"**Ревматичният ендокардит** е най-манифестната проява на ревматичната болест на сърцето. Засяга главно клапните платна — **ревматичен валвулит**, и може да доведе до трайни клапни деформации.\nРазличават се **4 форми на ревматичен ендокардит**:\n- **дифузен ендокардит**\n- **остър верукозен ендокардит**\n- **фиброзен ендокардит**\n- **рецидивиращ верукозен ендокардит**\nНай-често се увреждат клапите на лявата сърдечна половина:\n- **митрална клапа** — изолирано в 65–70% от случаите;\n- **митрална + аортна клапа** — в 20–25%;\n- **аортна клапа** — изолирано в 15–20%.\nТрикуспидалната и белодробната клапа се засягат по изключение.\n### Макроскопски\nЗасегнатите клапни платна са **зачервени, оточни и задебелени**.\nПо предсърдната повърхност на митралната клапа и камерната повърхност на аортната клапа, най-вече по клапните ръбове, се виждат множество дребни **сиво-розови възелчета** с размер 1–2 mm.\nТе се наричат **веруки / брадавици** и са подредени в редица като „зърна на броеница“. Плътно са прикрепени към подлежащата тъкан. Тази картина се означава като **ревматичен верукозен ендокардит**.\n### Микроскопски\n**Верките** са изградени от **тромбоцитни агрегати и фибрин** и не съдържат микроорганизми, което ги отличава от вегетациите при инфекциозен ендокардит.\nВ подлежащата спонгиозна тъкан на клапата се наблюдава инфилтрация от **мононуклеарни левкоцити**, а рядко — абортивни **грануломи на Ашоф**.\nХарактерен белег на ревматичния валвулит е появата на **капиляри и артериоли в клапните платна**, които нормално са аваскуларни.\n### Изход\nОстрите възпалителни изменения могат да отзвучат напълно, но по-често тромботичните вегетации се **организират** и се заместват от фиброзна тъкан.\nТова води до:\n- склеротично уплътняване и задебеляване на клапните платна;\n- срастване по ръбовете;\n- трайни клапни деформации.\nОбилната васкуларизация на засегнатите клапи е важен микроскопски белег за **постревматична природа** на клапния порок.\nПри хронифициране се развива **фиброзен ендокардит**. Най-характерно е засягането на митралната клапа, при което срастването на комисурите и деформацията на клапните платна водят до стеноза с типичен макроскопски вид на **„уста на риба“**.\nОбилната васкуларизация на засегнатите клапи е важен микроскопски белег за постревматична природа на клапния порок.\" id=\"note-1778168201055-10\">Ревматичен ендокардит от 27-ма тема</span></h4><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Хронична ревматична болест на сърцето</h2><p>Хроничната ревматична болест на сърцето се развива след продължителен латентен период — средно <strong>15–20 години</strong> след острата възпалителна фаза.</p><p>Морфогенезата на хронифицирането не е напълно изяснена. В резултат на организацията и фиброзата клапите стават необратимо деформирани. Цикатрициалното им задебеляване може да доведе до:</p><ul><li><strong>клапна стеноза</strong> — намаляване на диаметъра на клапното отвърстие;</li><li><strong>клапна инсуфициенция</strong> — непълно затваряне и връщане на кръв назад.</li></ul><p>Клапните стенози и инсуфициенции причиняват продължително <strong>обемно или тенсионно натоварване</strong> на миокарда. Сърцето се адаптира първоначално чрез <strong>хипертрофия</strong>, а по-късно и чрез <strong>дилатация</strong> на кухините, докато настъпи <strong>сърдечна недостатъчност</strong>.</p><p>Консервативната терапия може временно да подпомогне миокардната функция, но радикална корекция на хемодинамиката се постига чрез оперативно отстраняване на увредената клапа и имплантиране на <strong>клапна протеза</strong>.</p><p>Хроничният ревматичен митрален валвулит по-често води до <strong>митрална стеноза</strong>, отколкото до инсуфициенция.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 32. Лупус – диагностични критерии. Етиология, патогенеза, морфологични промени.</h1><p><strong>Системният лупус еритематодес (СЛЕ)</strong> е мултисистемно автоимунно заболяване с разнообразни прояви и вариабилно протичане.</p><p>Среща се най-често между <strong>20–40-годишна възраст</strong> и засяга жените значително по-често от мъжете — около <strong>9:1</strong>.</p><h2>Етиология и патогенеза</h2><p>Причината за СЛЕ остава неизвестна, но наличието на широк спектър от автоантитела показва, че основният дефект е нарушение на <strong>автотолерантността </strong>— т.е. загуба на имунна ареактивност към собствените антигени.</p><p>В резултат се образуват множество автоантитела, които увреждат тъканите директно или чрез <strong>имунни комплекси</strong>.</p><p>Основни групи автоантитела са:</p><ul><li>антитела срещу ядрени и цитоплазмени компоненти на клетката;</li><li>антитела срещу мембранни антигени на кръвни клетки — еритроцити, лимфоцити и тромбоцити. </li><li>Водещо значение имат <strong>антинуклеарните антитела (ANA)</strong>.</li></ul><p>Възникването на тези антитела се свързва с <strong>генетично предразположение</strong>, фактори на околната среда, медикаменти и полови хормони. СЛЕ може да бъде индуциран от медикаменти като <strong>hydralazine</strong> и <strong>procainamide</strong>. Естрогените и оралните контрацептиви също могат да благоприятстват заболяването.</p><p>В патогенезата участва генерализирана поликлонална активация на <strong>В-лимфоцитите</strong>, вероятно вследствие на хиперактивност на <strong>CD4+ Т-хелперите</strong>.</p><p><i>Автоантителата са основните медиатори на тъканното увреждане</i>. Повечето системни лезии се дължат на имунни комплекси, особено комплекси <strong>ДНК–анти-ДНК</strong>, които се отлагат в стените на малки артерии и артериоли в кожата и в базалните мембрани на бъбречните гломерули. Това активира комплемента и води до възпалителна реакция — <strong>свръхчувствителност тип III.</strong></p><p>Антителата срещу кръвни клетки водят до тяхната деструкция и фагоцитоза. <strong>Антинуклеарните антитела </strong>реагират с ядрата на увредени клетки, които губят нормалната си хроматинова структура и се превръщат в хомогенни, интензивно оцветяващи се <strong>хематоксилинови телца</strong>.</p><p>Техен in vitro корелат е<strong> LE-клетката</strong> — неутрофил или макрофаг, който е фагоцитирал денатурирано ядро на друга увредена клетка.</p><h2>Морфология</h2><p>Морфологичните промени при СЛЕ са свързани главно с отлагане на имунни комплекси. Най-често се засягат <strong>малките съдове, кожата, серозните обвивки, бъбреците и сърцето</strong>.</p><h3>Васкулит</h3><p>Особено характерен е васкулитът на <strong>малките артерии и артериоли</strong>. Наблюдават се <strong>фибриноидни отлагания </strong>в медията и периваскуларна инфилтрация от лимфоцити и плазматични клетки.</p><p>В съдовите стени се доказват <strong>имуноглобулини, C3-компонент на комплемента и фибриноген</strong>. В по-късните стадии настъпва фиброзно задебеляване на стената и стеноза на лумена.</p><h3>Кожа</h3><p>Кожните изменения се срещат при около <strong>50%</strong> от болните. Типичен е еритематозен или макулопапулозен обрив по носа и бузите с форма на <strong>„пеперуда“</strong>.</p><p><strong>Микроскопски</strong> се наблюдават вакуолна дегенерация в базалните слоеве на епидермиса, оток в дермо-епидермалната зона и васкулит на малките съдове. Характерно е отлагането на имуноглобулини по границата между епидермис и дерма — <strong>LE-ивица</strong>.</p><h3>Серозни обвивки</h3><p>Плеврата и перикардът често показват възпалителни промени със <strong>серозни или серо-фибринозни изливи</strong> в острия стадий.</p><h3>Бъбреци</h3><p>Бъбречното увреждане е една от най-важните прояви на СЛЕ. Почти всички болни имат някаква форма на <strong>гломерулонефрит</strong>, а <strong>бъбречната недостатъчност </strong>е най-честата причина за смърт.</p><h3>Сърце</h3><p>Сърдечно-съдовата система се засяга с <strong>перикардит</strong>, обикновено серозен, и по-рядко с <strong>миокардит</strong>, представен от неспецифични инфилтрати от лимфоцити и макрофаги.</p><p>Типичен е <strong>небактериалният верукозен ендокардит на Libman-Sacks</strong>, който най-често засяга <strong>митралната клапа</strong>. По клапните платна се виждат неправилни грануларни отлагания с големина 1–3 mm по двете им повърхности.</p><p>При много болни още в млада възраст се развива <strong>стенозираща атеросклероза на коронарните артерии</strong>, клинично проявена с ангина пекторис или миокарден инфаркт. Причината се свързва с увреждане на коронарния ендотел от автоантитела или имунни комплекси.</p><h3>Централна нервна система</h3><p>ЦНС често се засяга и може да даде огнищна неврологична симптоматика или невропсихиатрични прояви. </p><p>Увреждането се дължи на съдови лезии, които причиняват <strong>исхемия </strong>или мултифокални церебрални микроинфаркти.</p><h3>Стави</h3><p>Често се засягат коленни, глезенни и лакътни стави. Наблюдават се оток и неспецифична мононуклеарна възпалителна инфилтрация на синовиалната мембрана.</p><p>За разлика от ревматоидния артрит, ставното засягане при СЛЕ не води до трайни анатомични изменения и деформации.</p><h3>Слезка</h3><p>Слезката може да бъде умерено увеличена, със задебелена капсула и фоликулна хиперплазия. </p><p>Около централните фоликулни артериоли се наблюдава характерна концентрична периваскуларна фиброза, наподобяваща „<strong>люспи на лук</strong>“ — o<i>nion skin lesions</i>.</p><h2>Протичане</h2><p>Протичането на СЛЕ е силно вариабилно и трудно предсказуемо. При някои болни заболяването протича доброкачествено, само с кожни прояви. В повечето случаи обаче има периоди на <strong>обостряне и ремисии</strong>.</p><p>С прилагането на кортикостероидна и имуносупресивна терапия над <strong>70%</strong> от болните преживяват повече от 10 години след началото на заболяването. Най-честата причина за смърт е <strong>бъбречната недостатъчност</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 33. Ревматоиден артрит – морфологична характеристика. Особени форми на ревматоиден артрит.</h1><p><strong style=\"color: rgb(31, 41, 55)\">Ревматоидният артрит (РА)</strong><span style=\"color: rgb(31, 41, 55)\"> е системно хронично възпалително заболяване, което засяга предимно ставите. Основната морфологична проява е </span><strong style=\"color: rgb(31, 41, 55)\">негноен пролиферативен синовит</strong><span style=\"color: rgb(31, 41, 55)\">.</span></p><p>При прогресия заболяването води до разрушаване на <strong>ставния хрущял</strong> и подлежащата кост, с последваща <strong>анкилоза</strong> на ставата. При развитие на екстраартикуларни увреждания — кожа, сърце, скелетни мускули — промените могат да наподобяват СЛЕ или склеродерма.</p><p>Заболяването се проявява най-често между <strong>2-ро и 4-то десетилетие</strong> и засяга жените <strong>3–5 пъти по-често</strong> от мъжете.</p><h2>Патогенеза</h2><p>РА има <strong>имунна генеза</strong> и е свързан с генетично предразположение. Точният механизъм не е напълно изяснен.</p><p>При предразположени индивиди заболяването вероятно започва с активиране на <strong>CD4+ helper T-клетки</strong> в отговор на артритогенен агент — възможно микробен агент или автоантиген.</p><p>Активираните Т-клетки продуцират цитокини, които:</p><ul><li>активират клетки в ставното пространство и стимулират отделяне на провъзпалителни фактори и тъканно-разграждащи ензими;</li><li>стимулират пролиферацията на синовиоцити и фибробласти чрез макрофагиални цитокини като <strong>IL-1</strong> и <strong>TGF-β</strong>;</li><li>активират В-клетките, което води до продукция на антитела, включително срещу автоантигени.</li></ul><p>При около <strong>80%</strong> от болните в серума и ставната течност се открива <strong>ревматоиден фактор (RF)</strong> — най-често IgM антитела, насочени срещу собствени IgG. Те могат да образуват имунни комплекси, които се отлагат в ставите и други тъкани, активират комплемента и причиняват възпаление и тъканно увреждане — <strong>васкулити, плеврит, перикардит</strong>. Ролята на RF не е напълно доказана, тъй като около 20% от болните са серонегативни.</p><h2>Макроскопски</h2><p>РА се проявява със <strong>симетрично засягане</strong> на малките стави на ръцете и стъпалата, както и на глезенните, коленните и лакътните стави.</p><h2>Микроскопски</h2><p>Наблюдава се <strong>хроничен синовит</strong>, който се характеризира с:</p><ul><li>пролиферация и хиперплазия на <strong>синовиоцитите</strong>;</li><li>силна васкуларизация вследствие на <strong>ангиогенеза</strong>;</li><li>обилни периваскуларни инфилтрати от <strong>CD4+ T-лимфоцити</strong>, плазматични клетки и макрофаги;</li><li>отлагане на <strong>фибрин</strong> и неутрофили по синовиалната повърхност и в ставното пространство;</li><li>повишена активност на <strong>остеокластите</strong>, водеща до ерозия на подлежащата кост.</li></ul><p>Характерна структура е <strong>панусът</strong> — разраснала синовия, изградена от пролиферирали синовиоцити, възпалителни клетки, гранулационна и фиброзна съединителна тъкан. Панусът превръща синовиалната мембрана в дебела, оточна вилозна маса, която разрушава ставния хрущял и понякога субартикуларната кост.</p><p>Ако панусът изпълни цялото ставно пространство, последващата <strong>фиброза и калцификация</strong> могат да доведат до трайна <strong>анкилоза</strong>.</p><h2>Ревматоидни възли</h2><p>При около <strong>25%</strong> от болните се развиват <strong>ревматоидни подкожни възли</strong>, най-често по екстензорната повърхност на предмишницата или в области, подложени на механичен натиск.</p><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-06/text-editor-images/2026/05/1778093990274-image.png &quot;width=100%&quot;)\" id=\"note-1778093991851-9\">Макроскопски</span> </strong>са плътни, овални или кръгли възли с диаметър до <strong>2 cm</strong>.</p><p><strong><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-06/text-editor-images/2026/05/1778094039972-image.png &quot;width=100%&quot;)\" id=\"note-1778094041294-10\">Микроскопски</span></strong> се характеризират с централна <strong>фибриноидна некроза</strong>, заобиколена от палисадно подредени епителоидни клетки, фибробласти, макрофаги и лимфоцити.</p><h2>Клинично протичане</h2><p>Протичането е вариабилно. След около 10 години при част от болните заболяването се стабилизира или може да регресира. В други случаи прогресира с обостряния и ремисии, като след 10–20 години може да доведе до трайни ставни увреждания.</p><p>РА може да се усложни с <strong>генерализирана амилоидоза</strong>, която е една от причините за смърт при тези болни.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 34. Системна склероза (склеродермия) – морфологична характеристика. Дерматомиозит.</h1><p><strong>Системната склероза</strong> е заболяване, характеризиращо се с генерализирано <strong>фиброзиране на съединителната тъкан</strong> на дермата и интерстициалната съединителна тъкан на вътрешните органи.</p><p>Най-характерни са <strong>кожните лезии</strong>, които се срещат при около <strong>95%</strong> от болните. Засягането на бъбреците, сърцето и скелетните мускули може да бъде животозастрашаващо. Заболяването започва най-често между <strong>3-то и 5-то десетилетие</strong> и засяга жените около <strong>3 пъти по-често</strong> от мъжете.</p><h2>Класификация</h2><p>Различават се две основни форми:</p><ul><li><strong>Дифузна склеродерма</strong> — с разпространени кожни увреждания, бърза прогресия и ранно висцерално засягане.</li><li><strong>Ограничена склеродерма</strong> — с по-слабо кожно засягане, често по лицето и пръстите. Висцералните увреждания настъпват по-късно и протичането е по-доброкачествено.</li></ul><p>Ограничената форма се означава още като <strong>CREST-синдром</strong>, включващ: <strong>calcinosis</strong>, <strong>Raynaud феномен</strong>, езофагеални мотилитетни нарушения, <strong>sclerodactylia</strong> и <strong>teleangiectasia</strong>.</p><h2>Етиология и патогенеза</h2><p>Етиологията е неизвестна. Заболяването се разглежда като резултат от <strong>абнормна имунна активация</strong> и <strong>микроваскуларно увреждане</strong>.</p><p>Приема се, че неизвестен патогенен фактор активира <strong>CD4+ Т-клетки</strong>, които се натрупват в кожата. Те отделят цитокини, активиращи макрофаги и мастоцити, с освобождаване на <strong>фиброгенни и растежни фактори</strong>. Активират се и В-клетките, което се проявява с <strong>хипергамаглобулинемия</strong> и наличие на <strong>антинуклеарни антитела (ANA)</strong>.</p><p>Ранна и постоянна проява е увреждането на малките съдове. Развиват се <strong>интимална и периваскуларна фиброза</strong>, които стесняват съдовия лумен и водят до исхемични лезии. Повтарящите се ендотелни увреждания са последвани от агрегация на тромбоцити и отделяне на фактори като <strong><span class=\"editor-note\" data-note=\"**PDGF** (*platelet-derived growth factor*) е **тромбоцитен растежен фактор**\" id=\"note-1778094235549-11\">PDGF</span></strong>, което усилва фиброзата и стенозата на малките съдове.</p><h2>Морфология</h2><p>Системната склероза може да засегне почти всеки орган, но най-изразени са промените в <strong>кожата, стомашно-чревния тракт, ставите, бъбреците, белите дробове и сърцето</strong>.</p><h3>Кожа</h3><p>Кожните промени обикновено започват от <strong>пръстите и дисталните части на ръцете</strong>, след което се разпространяват към раменете и лицето. Фиброзата на дермата води до изтъняване и изостряне на пръстите — <strong>„пръсти на Мадона“</strong>. При засягане на лицето се оформя <strong>„<span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-06/text-editor-images/2026/05/1778094369801-image.png &quot;width=100%&quot;)\" id=\"note-1778094372725-12\">масковидно лице</span>“</strong>.</p><p><strong>Микроскопски</strong> в ранните стадии има оток и периваскуларни инфилтрати от <strong>CD4+ Т-клетки</strong>. Капилярите и малките артерии са със задебелени базални мембрани, ендотелно увреждане и частична оклузия.</p><p>В късните стадии отокът се замества от прогресираща <strong>фиброза и колагенизация на дермата</strong>, атрофия на кожните придатъци и епидермиса, както и хиалинно задебеляване на артериолите и капилярите. При <strong>CREST-синдром</strong> могат да се открият калциеви отлагания в подкожната тъкан.</p><h3>Стомашно-чревен тракт</h3><p>Засяга се при около <strong>90%</strong> от болните. Развива се прогресивна атрофия и заместване с фиброзна тъкан на мускулния слой на <strong>хранопровода</strong> и тънките черва. Лигавицата е изтънена, а <strong>lamina propria</strong> и субмукозата са фиброзно задебелени.</p><h3>Стави</h3><p>В ранните стадии се развива неспецифичен <strong>синовит</strong>, а по-късно — <strong>синовиална склероза</strong>. Склерозират и периартикуларните тъкани, което ограничава подвижността на ставите.</p><h3>Бъбреци</h3><p>Бъбречни увреждания има при около <strong>2/3</strong> от случаите. Характерно е задебеляването на стените на <strong>интерлобуларните артерии</strong>. При част от болните се развива артериална хипертония, понякога с белези на <strong>малигнена хипертония</strong>.</p><h3>Бели дробове</h3><p>Белите дробове се засягат при повече от <strong>50%</strong> от болните. Промените се проявяват като <strong>белодробна хипертония</strong> или <strong>дифузна интерстициална фиброза</strong>, съпроводена със задебеляване на стените на малките кръвоносни съдове.</p><h3>Сърце</h3><p>В миокарда при около <strong>30%</strong> от болните се наблюдава огнищна <strong>интерстициална фиброза</strong> със задебеляване на интрамиокардните артериоли. Тя се дължи на микроваскуларното увреждане и последващата исхемия.</p><h2>Протичане</h2><p>Протичането на <strong>дифузната системна склероза</strong> е трудно предвидимо. При повечето болни заболяването прогресира бавно в продължение на години, като 10-годишната преживяемост варира приблизително между <strong>35% и 70%</strong>.</p><p>При <strong>ограничената склеродерма / CREST-синдром</strong> кожното засягане е ограничено и може да минат десетилетия преди появата на висцерални лезии.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 35. Вродени пороци на сърцето – класификация. Хемодинамични нарушения.</h1><p>Към тази група се отнасят <strong>вродени, макроскопски видими отклонения</strong> от нормалната структура на сърцето и близките големи съдове. Те нарушават нормалния кръвоток през сърдечните кухини и големите съдове.</p><p>В много случаи кръвта преминава по съкратени пътища през анатомични дефекти, което води до пренасочване на кръв към <strong>системното</strong> или <strong>белодробното кръвообращение</strong>. Така се създава абнормно функционално натоварване на едната или другата сърдечна половина.</p><p>Сърдечно-съдовата система показва вродени малформации по-често от други органи и системи. Значението им е голямо, тъй като съвременната кардиохирургия може успешно да коригира значителна част от тях.</p><h2>Етиология</h2><p>Етиологията не е напълно изяснена. Приема се участие на <strong>генетични фактори</strong>, което се подкрепя от честите сърдечни аномалии при хромозомни аберации и фамилно натрупване на малформации.</p><p>Вродени сърдечни пороци се срещат по-често при деца със <strong>синдром на Down</strong> и <strong>синдром на Turner</strong>. От факторите на околната среда значение имат тератогенни въздействия, напреднала възраст на родителите, родствени бракове, многоплодна бременност, употреба на алкохол и интензивно тютюнопушене.</p><h2>Най-чести видове</h2><p>Най-честите вродени пороци на сърцето и големите съдове са:</p><ul><li><strong>дефекти в междукамерния септум</strong> – около 30%;</li><li><strong>дефекти в междупредсърдния септум</strong> – около 10%;</li><li><strong>персистиращ артериален проток</strong> – около 10%;</li><li><strong>тетралогия на Fallot</strong> – около 6%.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-06/text-editor-images/2026/05/1778087158493-image.png &quot;width=100%&quot;)\" id=\"note-1778087160257-1\">Дефекти в междупредсърдния септум</span> (ASD)</h2><h3>Незатворен foramen ovale</h3><p>Проходимият след раждането <strong>foramen ovale</strong> не е истински дефект на междупредсърдната преграда, а хемодинамична пролука, действаща като клапен вентил.</p><p>Обикновено foramen ovale се затваря след 4-тата седмица от раждането. Макар и анатомично проходим при някои хора, той често остава функционално затворен. Въпреки това, при определени условия се развива <strong>ляво-десен шънт</strong>, тъй като по-високото налягане в лявото предсърдие изтласква кръв към дясното</p><p>Ако налягането в дясното предсърдие се повиши (при белодробна емболия или хипертония), вентилът се отваря в обратна посока. Това може да доведе до <strong>дясно-ляв шънт</strong> и <strong>парадоксална емболия</strong>.</p><h3><strong><span style=\"color: rgb(88, 129, 87)\"><span class=\"editor-note\" data-note=\"# Ostium primum дефекти\nРазположени са в долната половина на предсърдната преграда. Често се съчетават с малформации на **атриовентрикуларните клапи**.\n# Ostium secundum дефекти\nОтворът е разположен в предно-горната половина на предсърдната преграда, пред или около очертанията на овалната ямка.\nНай-тежката форма на предсърден септален дефект е пълната липса на предсърдна преграда — **трикухинно сърце**, при което има общо предсърдие и две камери.\" id=\"note-1778087418185-4\" style=\"\">Същински дефекти</span></span></strong></h3><h2>Клинично значение</h2><p>Клиничната изява зависи от размера на дефекта. Обикновено се развива <strong>ляво-десен шънт</strong> който води до хипертрофия и дилатация на дясната сърдечна половина.</p><p>Обемното натоварване в системата на белодробната артерия може да причини <strong>хипертензивни промени</strong> в нейните стени. При всички форми на предсърдни дефекти могат да се наблюдават <strong>парадоксални емболии</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-06/text-editor-images/2026/05/1778087195162-image.png &quot;width=100%&quot;)\" id=\"note-1778087196755-2\">Дефекти в междукамерната преграда</span> (VSD)</h2><p>Според локализацията дефектите в междукамерния септум се делят на <strong>мембранозни</strong> и <strong>мускулни</strong>.</p><ul><li><strong>Мембранозният дефект</strong> се намира високо, непосредствено под аортната клапа, в областта на <strong>pars membranacea</strong> на междукамерния септум.</li><li><strong>Мускулният дефект</strong> е разположен по-каудално, в мускулната част на септума.</li></ul><p>Хемодинамично обикновено има <strong>ляво-десен шънт</strong> — при систола лявата камера изтласква кръв през дефекта към дясната камера и белодробната артерия. При големи дефекти, над <strong>2 cm</strong>, към дясната камера преминава не само кръв с по-високо налягане, но и с по-голям обем. Това води до обемно натоварване на дясната камера и развитие на <strong>пулмонална хипертония</strong>.</p><p>Увеличеният белодробен кръвоток натоварва и лявото предсърдие и лявата камера, което води до <strong>хипертрофия</strong> на стените им.</p><p>Клиничното протичане зависи главно от размера на дефекта. При големи дефекти без оперативно лечение децата често умират през първата година от <strong>сърдечна недостатъчност</strong> или белодробни инфекции. При малки мускулни дефекти основната проява е силен систоличен шум, без значими функционални нарушения.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-06/text-editor-images/2026/05/1778087084134-image.png &quot;width=100%&quot;)\" id=\"note-1778087086217-0\">Персистиращ артериален прото</span>к (PDA)</h2><p><strong>Ductus arteriosus Botalli</strong> по време на вътреутробното развитие свързва белодробната артерия с аортата. Чрез него голяма част от кръвта от дясната камера преминава директно в аортата, заобикаляйки белите дробове.</p><p>При нормални условия протокът се затваря още през първия ден след раждането поради нарастващото кислородно насищане на кръвта. При персистирането му се образува <strong>ляво-десен шънт</strong> — кръв от аортата, където налягането е по-високо, преминава към белодробната артерия.</p><p>Това води до увеличен белодробен кръвоток, <strong>обемно свръхнатоварване на лявата камера</strong> и постепенно развитие на <strong>белодробна хипертония</strong>, която натоварва и дясната камера.</p><p>Прогнозата е относително добра. Без оперативна интервенция средната продължителност на живота е около <strong>40 години</strong>. Най-чести причини за смърт са прогресираща десностранна сърдечна недостатъчност и <strong>инфекциозен ендокардит</strong> на протока с тромбоемболични усложнения. Малформацията се коригира лесно хирургично.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-06/text-editor-images/2026/05/1778087235796-image.png &quot;width=100%&quot;)\" id=\"note-1778087237464-3\">Тетралогия на Fallot</span></h2><p><strong>Тетралогията на Fallot</strong> представлява комбинация от вродени пороци и адаптивни промени в сърцето.</p><p>Характеризира се с четири компонента:</p><ul><li><strong>дефект в междукамерния септум</strong>;</li><li><strong>яздеща аорта</strong> — изместена надясно над септалния дефект и получаваща кръв от двете камери;</li><li><strong>стеноза на изходящия път на белодробната артерия</strong>;</li><li><strong>хипертрофия на дясната камера</strong> като компенсаторна реакция.</li></ul><p>Хемодинамично основен проблем е задържането на кръв в дясната камера поради <strong>пулмоналната стеноза</strong>. Част от тази кръв преминава през септалния дефект към аортата, т.е. развива се <strong>дясно-ляв шънт</strong>. Това води до постъпване на смесена кръв в системното кръвообращение.</p><p>Протичането зависи от степента на пулмоналната стеноза. При по-слабо стеснение белите дробове се кръвоснабдяват достатъчно и цианозата е слабо изразена. При тежка стеноза рано се развива дясно-ляв шънт, белодробният кръвоток намалява, а белодробните съдове и лявото предсърдие стават хипопластични. Клинично се развиват <strong>тежка цианоза</strong> и обща хипоксия.</p><p>Без оперативна корекция средната преживяемост е около <strong>12 години</strong>, като децата с тежка пулмонална стеноза умират рано. Оперативната корекция дава добри резултати.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 36. Сърдечна недостатъчност – видове. Органни промени.</h1><p><strong>Сърдечната недостатъчност</strong> е клиничен синдром на нарушена помпена функция на сърцето. Сърцето не може да изтласква достатъчно количество кръв, необходимо за метаболитните нужди на тъканите.</p><p>Тъй като основната помпена работа се извършва от камерите, сърдечната недостатъчност обикновено се дължи на нарушена функция на едната или двете сърдечни камери. Много сърдечно-съдови заболявания могат да завършат със сърдечна недостатъчност.</p><h2>Етиология и патогенеза</h2><p>Сърдечната недостатъчност се дължи на две основни групи причини:</p><ul><li><strong>абнормно повишено работно натоварване</strong> на сърцето — обемно (клапни пороци и др.) или тенсионно (артериална хипертония);</li><li><strong>намалена контрактилна способност на миокарда</strong> — при миокардити, кардиомиопатии, миокардна фиброза.</li></ul><p>Често участват фактори и от двете групи. В отговор на повишено хемодинамично натоварване или нарушен контрактилитет сърцето включва компенсаторни механизми — основно <strong>хипертрофия на миокарда</strong> и <strong>дилатация на сърдечните кухини</strong>.</p><h3>Сърдечна хипертрофия</h3><p>Сърдечната хипертрофия е компенсаторна реакция на миокарда при повишена механична работа или трофични стимули. Тя се дължи на повишена белтъчна синтеза, увеличаване на размера на миоцитите и броя на саркомерите. Тъй като зрелите кардиомиоцити не се делят, <strong>хиперплазия не настъпва</strong>.</p><p><strong>Макроскопски:</strong> най-добър критерий е увеличеното <strong>сърдечно тегло</strong>, което може да достигне <strong>600–800 g</strong> при системна хипертония, митрална стеноза и ИБС. Дебелината на камерните стени също може да надвиши <span class=\"editor-note\" data-note=\"12 - 15 мм за лявата камера, 3 - 5 мм за дясната, 2 мм за предсърдията\" id=\"note-1778092774004-7\">нормалните стойности</span>.</p><p>Според вида на натоварването се различават:</p><ul><li><strong>концентрична хипертрофия</strong> — при тенсионно натоварване, напр. системна хипертония; стената е задебелена без значима дилатация;</li><li><strong>ексцентрична хипертрофия</strong> — при обемно натоварване, напр. митрална или аортна регургитация; хипертрофията се съчетава с дилатация на кухината.</li></ul><p><strong>Микроскопски:</strong> хипертрофираните миоцити са по-дълги и по-дебели от нормалните. Диаметърът им може да достигне <strong><span class=\"editor-note\" data-note=\"12 μm е норма\" id=\"note-1778092837590-8\">25 μm</span> и повече</strong>. Ядрата са уголемени, хиперхромни и с отсечени краища.</p><h3>Сърдечна дилатация</h3><p><strong>Сърдечната дилатация</strong> представлява разширение на сърдечните кухини. Настъпва при обемно свръхнатоварване, например при продължителни клапни пороци или в късните фази на системна хипертония.</p><p>Функционално дилатацията се обяснява със закона на <strong>Frank-Starling</strong> — колкото по-силно е изпълнена сърдечната кухина в диастола и колкото повече са разтегнати миоцитите, толкова по-силна е последващата систолна контракция.</p><p>Този механизъм обаче има граница. При прекомерна дилатация в камерите се задържа <strong>резидуална кръв</strong>, което допълнително натоварва сърцето. Дилатацията винаги се предшества или съпътства от хипертрофия, т.е. има картина на <strong>ексцентрична хипертрофия</strong>.</p><h2>Патофизиология</h2><p>Компенсаторните механизми — хипертрофия и дилатация — временно поддържат сърдечния дебит. След преминаване на критична граница те стават неефективни и се превръщат в допълнително бреме.</p><p>Хипертрофиралият миокард има повишена нужда от кръв и кислород, а прекомерната дилатация намалява ефективността на контракцията. Така <strong>ударният обем</strong> и <strong>сърдечният дебит</strong> прогресивно намаляват.</p><p><strong>Макроскопски </strong>сърцето при сърдечна недостатъчност е увеличено, с дилатирани камери и изтънени стени, като микроскопски могат да се видят белези на хипертрофия.</p><p>Степента на структурните промени не винаги отговаря на степента на дисфункция. Затова морфологично не винаги може да се различи компенсирано от декомпенсирано сърце.</p><p>Основните морфологични прояви на сърдечната недостатъчност се откриват в периферните органи и са резултат от <strong>хипоксия</strong> и <strong>венозен застой</strong>, причинени от недостатъчната циркулация.</p><h2>Видове според засегнатата сърдечна половина</h2><p>Лявата и дясната половина на сърцето обикновено не декомпенсират едновременно. Поради това клинично се различават <strong>лявостранна</strong> и <strong>дясностранна сърдечна недостатъчност</strong>.</p><p>Недостатъчността на едната половина обаче не може дълго да персистира изолирано, защото претоварва другата половина. В крайна сметка може да се развие <strong>тотална сърдечна недостатъчност</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лявостранна сърдечна недостатъчност</h2><p><strong>Лявостранната сърдечна недостатъчност</strong> най-често се причинява от <strong>ИБС</strong>, хипертонична болест, аортни и митрални клапни пороци и миокардни заболявания.</p><p>Морфологично <strong>лявата камера</strong> обикновено е <strong>хипертрофирана</strong>, а често и <strong>дилатирана</strong>.</p><p>Клиничните и морфологичните промени се дължат на два основни механизма:</p><ul><li>продължителна задръжка на кръв в <strong>белодробната циркулация</strong>;</li><li>намалено периферно кръвоснабдяване поради редуциран сърдечен дебит.</li></ul><h3>Белодробни промени</h3><p>При декомпенсация лявата камера не може да изтласква цялата кръв, която постъпва от белодробното кръвообращение. Кръвта се застоява в <strong>белодробните вени</strong>, налягането в тях се повишава и застоят се предава ретроградно към капилярите.</p><p>В резултат се развиват <strong>белодробен кръвен застой</strong> и <strong>белодробен оток</strong>.</p><h3>Бъбречни промени</h3><p>Намаленият сърдечен дебит води до <strong>хипоперфузия на бъбреците</strong>, която активира <strong>ренин-ангиотензин-алдостероновата система</strong>. Това причинява задръжка на <strong>натрий и вода</strong>.</p><p>Тази компенсаторна реакция увеличава обема на циркулиращата кръв, но допълнително утежнява <strong>белодробния оток</strong>.</p><h3>Мозъчни промени</h3><p>При напреднала сърдечна недостатъчност намаленото мозъчно кръвоснабдяване води до <strong>мозъчна хипоксия</strong> и <strong>енцефалопатия</strong>.</p><p>Клинично се проявява с раздразнителност, нарушена концентрация и неспокойствие, които могат да прогресират до <strong>ступор и кома</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Дясностранна сърдечна недостатъчност</h2><p><strong>Изолирана дясностранна сърдечна недостатъчност</strong> е рядка. В чиста форма се среща най-често при хронична <strong>белодробна хипертония</strong>, свързана с дифузни заболявания на белодробния паренхим или белодробните съдове. Тогава се означава като <strong>cor pulmonale</strong>.</p><p>В тези случаи дясната камера е <strong>тенсионно свръхнатоварена</strong> поради повишената резистентност в белодробната циркулация. Хипертрофията и дилатацията са ограничени главно в <strong>дясната камера и дясното предсърдие</strong>.</p><p>Най-често обаче ДСН е последица от <strong>лявостранна сърдечна недостатъчност</strong>, защото повишеното налягане в малкия кръг натоварва дясната сърдечна половина.</p><h2>Морфологични промени</h2><p>Морфологичните промени при чиста ДСН се дължат на <strong>венозен застой в системната и порталната циркулация</strong>, при минимален застой в белите дробове.</p><p>Засегнати са главно <strong>черният дроб, слезката, бъбреците, мозъкът и подкожната тъкан</strong>.</p><h3>Черен дроб</h3><p>Черният дроб е увеличен по размер и маса поради хроничния венозен застой — <strong>застойна хепатомегалия</strong>.</p><p>На срез има вид на <strong>мускатов черен дроб (hepar muscatum)</strong> — червени, разширени и кръвонапълнени центрове на делчетата, заобиколени от по-бледи периферни зони с мастна дегенерация.</p><p>Ако към венозния застой се прибави и лявостранна недостатъчност, тежката хипоксия може да доведе до <strong>центролобуларни некрози</strong>. При продължителна ДСН централните части на делчетата фиброзират и се развива <strong>кардиачна склероза / кардиачна цироза</strong>.</p><h3>Слезка</h3><p>Повишеното налягане в порталната система води до <strong>застойна спленомегалия</strong>. Слезката е увеличена по размер и тегло.</p><p>Микроскопски се наблюдават <strong>дилатация на синусите</strong>, фиброзиране на синусоидните стени и капсулата.</p><h3>Бъбреци</h3><p>В бъбреците хроничният венозен застой и хипоксията са по-силно изразени в сравнение с ЛСН. Това води до по-голяма <strong>ретенция на течности</strong> и по-тежки периферни отоци.</p><h3>Главен мозък</h3><p>Венозният застой и хипоксията причиняват промени и симптоми, подобни на тези при ЛСН — раздразнителност, неспокойствие, нарушена концентрация, а при тежки случаи ступор и кома.</p><h3>Подкожна тъкан и серозни кухини</h3><p>В подкожната тъкан, особено около глезените и ниско разположените части на тялото, се развиват <strong>отоци</strong> — характерен белег на хронична ДСН.</p><p>При тежки случаи отоците стават генерализирани — <strong>аназарка</strong>. Могат да се развият и трансудатни изливи:</p><ul><li><strong>hydrothorax</strong> — в плевралните кухини;</li><li><strong>hydropericard</strong> — в перикардната торбичка.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Тотална сърдечна недостатъчност</h2><p>При хронична сърдечна декомпенсация често се развива <strong>тотална сърдечна недостатъчност</strong>, която включва проявите както на лявостранна, така и на дясностранна недостатъчност.</p><p>ЛСН се проявява главно със застой в <strong>малкия кръг</strong>, ДСН — със застой в <strong>системната циркулация</strong>, а тоталната сърдечна недостатъчност — със застой и в двата кръга на кръвообращението.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 37. Кардиомиопатии – определение, видове, морфологична характеристика.</h1><p><strong>Синоним:</strong> Първични заболявания на миокарда.</p><p>Кардиомиопатиите се разделят на три основни групи според структурните и функционалните промени в сърцето:</p><ul><li><strong>дилатативна кардиомиопатия</strong></li><li><strong>хипертрофична кардиомиопатия</strong></li><li><strong>рестриктивна кардиомиопатия</strong></li></ul><p>Най-честа е <strong>дилатативната кардиомиопатия</strong>, а рестриктивната форма се среща рядко.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778168891261-image.png &quot;width=100%&quot;)\" id=\"note-1778168892726-15\">Дилатативна кардиомиопатия</span></h2><p><strong>Дилатативната кардиомиопатия</strong> се характеризира с <i><strong>контрактилна дисфункция</strong></i> на миокарда. Намалява систолният ударен обем, задържа се кръв по време на диастола и постепенно се развиват <strong>дилатация на сърдечните кухини</strong> и вторична хипертрофия.</p><p>Среща се във всяка възраст, включително при деца, но е най-честа между <strong>20 и 60 години</strong>.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778168917850-image.png &quot;width=100%&quot;)\" id=\"note-1778168906372-16\">Макроскопски</span></h3><p>Сърцето е с <strong>кълбовидна форма</strong> и увеличено тегло. Всички сърдечни кухини са дилатирани, особено камерите. Въпреки хипертрофията, дебелината на камерните стени може да изглежда нормална поради изразената дилатация.</p><p>Наблюдава се <strong>фокална миокардна и ендокардна фиброза</strong>. При около 50% от случаите се откриват <strong>пристенни тромби</strong> в предсърдията и камерите.</p><h3><span class=\"editor-note\" data-note=\"Оцветяване с Masson trichrome показва интерстициална фиброза — синьо оцветен колаген между миоцитите, характерен за дилатативна кардиомиопатия.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778169027649-image.png &quot;width=100%&quot;)\" id=\"note-1778169047766-17\">Микроскопски</span></h3><p>Промените са неспецифични. Наблюдават се <strong>интерстициална или огнищна фиброза</strong>, хипертрофия на миоцитите и групи от изтънени или атрофични миоцити.</p><p>В част от случаите има слаба хронична <strong>лимфоцитна възпалителна инфилтрация</strong>. Степента на морфологичните промени не винаги съответства на тежестта на сърдечната дисфункция и прогнозата.</p><h3>Еволюция</h3><p>Заболяването протича с бавно прогресираща <strong>сърдечна недостатъчност</strong>, често рефрактерна на терапия. Около половината от болните умират в рамките на 2 години, а около 25% преживяват повече от 5 години.</p><p>Смъртта настъпва най-често от прогресираща сърдечна недостатъчност, аритмии или тромбоемболии. При част от болните <strong>сърдечната трансплантация</strong> е единствена терапевтична възможност.</p><h2>Особени форми на дилатативна кардиомиопатия</h2><h3>Алкохолна кардиомиопатия</h3><p>Наблюдава се при хронична злоупотреба с алкохол, обикновено за повече от 10 години. Дължи се на директния токсичен ефект на алкохола върху миокарда или индиректно — чрез недохранване с дефицит на белтъци и витамини.</p><h3>Перипартум кардиомиопатия</h3><p>Развива се в късните срокове на бременността или няколко седмици след раждането. Причината е неизвестна, като се допуска поствъзпалителна генеза.</p><p>В около половината от случаите миокардната дисфункция се възстановява спонтанно, а дилатацията на сърдечните кухини изчезва в рамките на няколко месеца след раждането.</p><h3>Аритмогенна дисплазия на дясната камера</h3><p>Често е фамилно заболяване. Характеризира се с <strong>дясностранна сърдечна недостатъчност</strong> и ритъмни нарушения, най-често камерна тахиаритмия.</p><p><strong>Макроскопски</strong> дясната камера е със силно изтънена стена поради намален брой миоцити, обилна мастна инфилтрация и интерстициална фиброза.</p><p>Заболяването може да завърши с <strong>внезапна смърт</strong>, обусловена от аритмии.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778169493652-image.png &quot;width=100%&quot;)\" id=\"note-1778169494614-21\">Хипертрофична кардиомиопатия</span></h2><p><strong>Хипертрофичната кардиомиопатия</strong> е известна още като <strong>идиопатична хипертрофична субаортна стеноза</strong> и <strong>хипертрофична обструктивна кардиомиопатия</strong>.</p><p>Характеризира се с <strong>първична миокардна хипертрофия</strong>, мощна хиперкинетична контракция, нарушено диастолично пълнене и при около <strong>1/3 от случаите</strong> — обструкция на изходния тракт на лявата камера.</p><h3>Патогенеза</h3><p>При около <strong>50%</strong> от болните заболяването е фамилно, с <strong>автозомно-доминантно унаследяване</strong> и варираща експресия. Останалите случаи вероятно са спорадични.</p><p>В част от фамилните случаи се доказва мутация в гена за <strong>тежките вериги на β-миозина</strong>, основен контрактилен протеин в дебелите филаменти на саркомерите.</p><h3><span class=\"editor-note\" data-note=\"**A**: Макроскопски срез по късата ос с циркумферентна хипертрофия на лявата камера. Наблюдава се и изразена септална хипертрофия с неправилни цикатрикси в антеросепталната област. Забелязват се също изразени папиларни мускули и трабекули в лявата камера.\n**C**: Макроскопски срез по късата ос с циркумферентно задебеляване на лявата камера вследствие на хиперконтракция. Няма цикатрикси или изразена септална хипертрофия. Забелязват се и изразени папиларни мускули и трабекули в лявата камера.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778169289199-image.png &quot;width=100%&quot;)\" id=\"note-1778169191681-18\">Макроскопски</span></h3><p>Основен белег е <strong>масивната миокардна хипертрофия</strong>, най-силно изразена в <strong>лявата камера</strong> и <strong>междукамерния септум</strong>, без дилатация на камерите.</p><p>Сърцето е силно увеличено — над <strong>500–550 g</strong>, понякога до <strong>700–800 g</strong>. В повечето случаи септумът е по-силно задебелен от свободната стена на лявата камера — <strong>асиметрична септална хипертрофия</strong>.</p><p>Горната част на септума е особено задебелена, с куполовидна форма и проминира в кухината на лявата камера. При систола предното платно на митралната клапа може да се притиска към хипертрофирания септум и да предизвика <strong>обструкция на изходния тракт</strong>.</p><p>Повтарящото се притискане води до <strong>фиброзно задебеляване на предното митрално платно</strong> и фиброза на срещуположния септален ендокард — „огледален отпечатък“ от платното.</p><h3><span class=\"editor-note\" data-note=\"**B**: Микроскопски срез показва безредно разположение на отделни миоцити и миоцитни снопчета, с хиперхромни ядра. Има увеличено количество интерстициален колаген — находки, съответстващи на HCM. Оцветяване с хематоксилин-еозин.\n**D**: Микроскопски срез показва хиперконтракция на миоцитите с контрактурни ивици в иначе нормални миоцити. Няма увеличено количество интерстициален колаген. Оцветяване с хематоксилин-еозин.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778169347765-image.png &quot;width=100%&quot;)\" id=\"note-1778169359705-19\">Микроскопски</span></h3><p>Наблюдава се изразена <strong>хипертрофия на миоцитите</strong>, с напречен диаметър над <strong>40 μm</strong>.</p><p>Характерен микроскопски белег е <strong>безредното разположение на миоцитите и миоцитните снопчета</strong> в областта на септалната хипертрофия. Налице е и изразена <strong>интерстициална и заместителна фиброза</strong>.</p><h3>Клинично протичане</h3><p>Заболяването често се съпровожда с <strong>камерни аритмии</strong>, които могат да доведат до <strong>внезапна сърдечна смърт</strong>. Това е една от най-честите причини за внезапна смърт при млади атлети.</p><p>В по-късните стадии прогресиращата миокардна фиброза може да доведе до <strong>сърдечна недостатъчност</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2><span class=\"editor-note\" data-note=\"![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778169486195-image.png &quot;width=100%&quot;)\" id=\"note-1778169487332-20\">Рестриктивна кардиомиопатия</span></h2><p><strong>Рестриктивната кардиомиопатия</strong> се характеризира с намалена податливост на камерите към диастолично разширение. Това води до ограничено <strong>диастолично пълнене</strong> и намален систолен ударен обем.</p><h3>Патогенеза</h3><p>Главна причина е <strong>ендомиокардната фиброза</strong> — заболяване с неясна етиология, срещано предимно в страни с тропически климат.</p><p>По-рядко се развива като последица от <strong>еозинофилен ендомиокардит на Löffler</strong>, който се среща в страни с умерен климат и също протича с ендомиокардна фиброза и големи пристенни тромби.</p><h3><span class=\"editor-note\" data-note=\"**A**: Сърдечен препарат, срязан така, че да се виждат четирите кухини: малките нехипертрофирали камери изглеждат като придатъци към силно дилатираните предсърдия. Обърни внимание, че липсват заболявания на перикарда, ендокарда или клапите.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-07/text-editor-images/2026/05/1778169547023-image.png &quot;width=100%&quot;)\" id=\"note-1778169602553-22\">Макроскопски</span></h3><p>Камерният ендокард е силно задебелен, понякога до няколко милиметра. Има <strong>седефенобял цвят</strong> и е много плътен.</p><p>Тези промени са резултат от организация на масивни <strong>мурални тромби</strong>, образувани в по-ранните фази на заболяването.</p><h3>Микроскопски</h3><p>Наблюдават се широки прослойки от <strong>безклетъчен колаген</strong> и <strong>интерстициална фиброза</strong> в подлежащите слоеве на миокарда.</p><h3>Протичане</h3><p>Заболяването води до прогресираща <strong>сърдечна недостатъчност</strong> и чести <strong>тромбоемболии</strong>, които са основни причини за смърт.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 38. Тумори на сърцето.</h1><p>Начало.</p><h1 style=\"text-align: center\"><br></h1>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
